# Asset minimi incorporati: consentono al gestionale di partire anche se nella cartella
# manca il modello Word o il logo. Se i file sono gia' presenti, non vengono sovrascritti.
EMBEDDED_TEMPLATE_ZLIB_B64 = """"""
EMBEDDED_LOGO_ZLIB_B64 = """"""


def _write_embedded_asset_if_missing(path: Path, payload_b64: str) -> None:
    try:
        if path.exists() and path.stat().st_size > 0:
            return
        raw = zlib.decompress(base64.b64decode(payload_b64.encode("ascii")))
        path.write_bytes(raw)
    except Exception:
        # Il gestionale resta utilizzabile: l'utente potra' indicare manualmente il modello.
        pass


def ensure_default_assets() -> None:
    _write_embedded_asset_if_missing(DEFAULT_TEMPLATE, EMBEDDED_TEMPLATE_ZLIB_B64)
    _write_embedded_asset_if_missing(LOGO_FILE, EMBEDDED_LOGO_ZLIB_B64)


ensure_default_assets()

