# -----------------------------------------------------------------------------
# Utilita' generali
# -----------------------------------------------------------------------------

def now_iso() -> str:
    return datetime.now().strftime("%Y-%m-%d %H:%M:%S")


def today_it() -> str:
    return datetime.now().strftime("%d/%m/%Y")


def normalize_space(value: Any) -> str:
    if value is None:
        return ""
    text = str(value)
    text = text.replace("\u00a0", " ")
    text = text.replace("\t", " ")
    text = re.sub(r"[ \f\v]+", " ", text)
    text = re.sub(r"\s+\n", "\n", text)
    text = re.sub(r"\n\s+", "\n", text)
    return text.strip()


def clean_inline(value: Any) -> str:
    text = normalize_space(value)
    text = text.strip(" :-|;,.\n\t")
    text = re.sub(r"\s{2,}", " ", text)
    return text


def simple(value: Any) -> str:
    text = normalize_space(value).lower()
    repl = {
        "à": "a", "è": "e", "é": "e", "ì": "i", "ò": "o", "ù": "u",
        "’": "'", "`": "'", "“": '"', "”": '"',
    }
    for a, b in repl.items():
        text = text.replace(a, b)
    return text


def strip_accents_for_key(value: Any) -> str:
    return simple(value).upper()


def dedupe_words(text: str) -> str:
    parts = [p.strip() for p in re.split(r"[;\n]+", text or "") if p.strip()]
    seen = set()
    out = []
    for part in parts:
        key = simple(part)
        if key and key not in seen:
            seen.add(key)
            out.append(part)
    return "; ".join(out)


def title_person(value: str) -> str:
    value = clean_inline(value)
    if not value:
        return ""
    particles = {"DI", "DE", "DEL", "DELLA", "D'", "DA", "LA", "LO", "VAN", "VON"}
    words = []
    for token in value.split():
        if token.upper() in particles:
            words.append(token.lower())
        elif "'" in token:
            words.append("'".join(p[:1].upper() + p[1:].lower() for p in token.split("'")))
        else:
            words.append(token[:1].upper() + token[1:].lower())
    return " ".join(words).replace("D'", "d'")


def upper_company(value: str) -> str:
    text = normalize_space(value)
    if not text:
        return ""
    # Non elimina il punto finale delle forme societarie (S.R.L., S.P.A.).
    text = text.strip(" :-|;,\n\t")
    text = re.sub(r"\s{2,}", " ", text)
    return text.upper()


def format_euro(value: Any) -> str:
    if value is None:
        return ""
    text = str(value).strip().replace("€", "").replace(" ", "")
    if not text:
        return ""
    # Gestione formato italiano: 1.000.000,00
    if "," in text:
        text = text.replace(".", "").replace(",", ".")
    else:
        # Se contiene punti come separatore migliaia e nessuna virgola
        if text.count(".") > 1:
            text = text.replace(".", "")
    try:
        number = float(text)
    except ValueError:
        return str(value)
    formatted = f"{number:,.2f}".replace(",", "X").replace(".", ",").replace("X", ".")
    return f"€ {formatted}"


def parse_euro(value: Any) -> float:
    text = str(value or "").strip().replace("€", "").replace(" ", "")
    if not text:
        return 0.0
    if "," in text:
        text = text.replace(".", "").replace(",", ".")
    elif text.count(".") > 1:
        text = text.replace(".", "")
    try:
        return float(text)
    except ValueError:
        return 0.0


def parse_percent(value: Any) -> float:
    text = str(value or "").strip().replace("%", "").replace(",", ".")
    try:
        return float(text)
    except ValueError:
        return 0.0


def format_percent(value: Any) -> str:
    n = parse_percent(value)
    if not n:
        return ""
    if n.is_integer():
        return f"{int(n)}%"
    return (f"{n:.2f}".replace(".", ",").rstrip("0").rstrip(",") + "%")


def build_descrizione_compenso(importo_finanziamento: Any, banca: Any) -> str:
    """Crea la descrizione compenso in automatico.

    Esempio: importo 500000 e banca IFIS ->
    erogato da banca IFIS di € 500.000,00
    """
    importo_num = parse_euro(importo_finanziamento)
    importo_txt = format_euro(importo_num) if importo_num else ""
    banca_txt = clean_inline(banca)

    if banca_txt:
        banca_descr = banca_txt
        # Se l'utente scrive solo "IFIS", la frase diventa "banca IFIS".
        # Se scrive gia' "Banca IFIS" o "Istituto...", non duplica la parola banca.
        if not re.search(r"\b(banca|istituto|finanziaria|credito)\b", banca_descr, flags=re.I):
            banca_descr = f"banca {banca_descr}"
        if importo_txt:
            return f"erogato da {banca_descr} di {importo_txt}"
        return f"erogato da {banca_descr}"

    if importo_txt:
        return f"di {importo_txt}"
    return ""


def normalize_financing_data(data: Dict[str, Any]) -> Dict[str, Any]:
    """Normalizza importi, percentuale, consulenza e descrizione compenso.

    L'importo consulenza viene sempre ricalcolato come:
    percentuale * importo finanziamento / 100.
    """
    importo_num = parse_euro(data.get("importo_finanziamento", ""))
    percent_num = parse_percent(data.get("percentuale", ""))

    if importo_num:
        data["importo_finanziamento"] = format_euro(importo_num)
    if percent_num:
        data["percentuale"] = format_percent(percent_num)
    if importo_num and percent_num:
        data["importo_consulenza"] = format_euro(importo_num * percent_num / 100.0)

    descrizione = build_descrizione_compenso(data.get("importo_finanziamento", ""), data.get("banca", ""))
    if descrizione:
        data["descrizione_compenso"] = descrizione
    return data


def safe_filename(name: str, fallback: str = "file") -> str:
    name = normalize_space(name) or fallback
    name = re.sub(r"[^A-Za-z0-9_ .-]+", "_", name)
    name = re.sub(r"\s+", "_", name).strip("._ ")
    return name[:80] or fallback


def copy_to_folder(src: str, folder: Path, prefix: str = "") -> str:
    if not src:
        return ""
    source = Path(src)
    if not source.exists():
        return ""
    stem = safe_filename((prefix + "_" if prefix else "") + source.stem)
    dest = folder / f"{stem}_{datetime.now().strftime('%Y%m%d_%H%M%S')}{source.suffix}"
    shutil.copy2(source, dest)
    return str(dest)


def open_file(path: str) -> None:
    if not path:
        return
    file_path = Path(path)
    if not file_path.exists():
        messagebox.showerror(APP_NAME, f"File non trovato:\n{path}")
        return
    system = platform.system().lower()
    try:
        if system == "windows":
            os.startfile(str(file_path))  # type: ignore[attr-defined]
        elif system == "darwin":
            subprocess.Popen(["open", str(file_path)])
        else:
            subprocess.Popen(["xdg-open", str(file_path)])
    except Exception:
        webbrowser.open(file_path.as_uri())


def print_file(path: str) -> None:
    if not path:
        return
    file_path = Path(path)
    if not file_path.exists():
        messagebox.showerror(APP_NAME, f"File non trovato:\n{path}")
        return
    system = platform.system().lower()
    try:
        if system == "windows":
            os.startfile(str(file_path), "print")  # type: ignore[attr-defined]
        elif system == "darwin":
            subprocess.Popen(["lp", str(file_path)])
        else:
            subprocess.Popen(["lp", str(file_path)])
    except Exception:
        open_file(path)


