CLIENT_FIELDS = [
    "denominazione", "partita_iva", "codice_fiscale", "sede_legale", "sede_operativa",
    "anno_costituzione", "settore_attivita", "codice_ateco", "mail_azienda",
    "telefono_azienda", "pec", "amministratore_nome", "amministratore_carica",
    "amministratore_luogo_nascita", "amministratore_data_nascita",
    "amministratore_residenza", "amministratore_codice_fiscale",
    "amministratore_dati_completi", "report_path",
]

MANDATO_FIELDS = [
    "client_id", "data_mandato", "stato", "responsabile", "oggetto", "note", "allegato_path",
    "importo_finanziamento", "percentuale", "importo_consulenza", "banca",
    "descrizione_compenso", "luogo", "docx_path", "pdf_path",
]


class Database:
    def __init__(self, path: Path = DB_PATH):
        self.path = path
        self.conn = sqlite3.connect(str(path))
        self.conn.row_factory = sqlite3.Row
        self.init_schema()

    def init_schema(self) -> None:
        cur = self.conn.cursor()
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS clients (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                created_at TEXT,
                updated_at TEXT,
                denominazione TEXT,
                partita_iva TEXT,
                codice_fiscale TEXT,
                sede_legale TEXT,
                sede_operativa TEXT,
                anno_costituzione TEXT,
                settore_attivita TEXT,
                codice_ateco TEXT,
                mail_azienda TEXT,
                telefono_azienda TEXT,
                pec TEXT,
                amministratore_nome TEXT,
                amministratore_carica TEXT,
                amministratore_luogo_nascita TEXT,
                amministratore_data_nascita TEXT,
                amministratore_residenza TEXT,
                amministratore_codice_fiscale TEXT,
                amministratore_dati_completi TEXT,
                report_path TEXT
            )
            """
        )
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS visure (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                client_id INTEGER,
                path TEXT,
                uploaded_at TEXT,
                extracted_json TEXT,
                confronto_json TEXT,
                FOREIGN KEY(client_id) REFERENCES clients(id)
            )
            """
        )
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS mandati (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                created_at TEXT,
                updated_at TEXT,
                client_id INTEGER,
                data_mandato TEXT,
                stato TEXT,
                responsabile TEXT,
                oggetto TEXT,
                note TEXT,
                allegato_path TEXT,
                importo_finanziamento TEXT,
                percentuale TEXT,
                importo_consulenza TEXT,
                banca TEXT,
                descrizione_compenso TEXT,
                luogo TEXT,
                docx_path TEXT,
                pdf_path TEXT,
                FOREIGN KEY(client_id) REFERENCES clients(id)
            )
            """
        )
        self.conn.commit()
        self.ensure_columns("clients", {field: "TEXT" for field in CLIENT_FIELDS})
        self.ensure_columns("mandati", {field: "TEXT" for field in MANDATO_FIELDS if field != "client_id"})
        self.ensure_columns("mandati", {"client_id": "INTEGER"})

    def ensure_columns(self, table: str, columns: Dict[str, str]) -> None:
        cur = self.conn.cursor()
        existing = {row[1] for row in cur.execute(f"PRAGMA table_info({table})").fetchall()}
        for col, col_type in columns.items():
            if col not in existing:
                cur.execute(f"ALTER TABLE {table} ADD COLUMN {col} {col_type}")
        self.conn.commit()

    def save_client(self, data: Dict[str, str], client_id: Optional[int] = None) -> int:
        clean = {field: clean_inline(data.get(field, "")) for field in CLIENT_FIELDS}
        # Per i campi lunghi lasciamo i newline ordinati
        clean["amministratore_dati_completi"] = normalize_space(data.get("amministratore_dati_completi", ""))
        if client_id:
            cols = ", ".join(f"{field} = ?" for field in CLIENT_FIELDS)
            vals = [clean[field] for field in CLIENT_FIELDS] + [now_iso(), client_id]
            self.conn.execute(f"UPDATE clients SET {cols}, updated_at = ? WHERE id = ?", vals)
            self.conn.commit()
            return int(client_id)
        vals = [now_iso(), now_iso()] + [clean[field] for field in CLIENT_FIELDS]
        placeholders = ", ".join("?" for _ in vals)
        fields = ", ".join(["created_at", "updated_at"] + CLIENT_FIELDS)
        cur = self.conn.execute(f"INSERT INTO clients ({fields}) VALUES ({placeholders})", vals)
        self.conn.commit()
        return int(cur.lastrowid)

    def get_clients(self) -> List[sqlite3.Row]:
        return self.conn.execute("SELECT * FROM clients ORDER BY denominazione COLLATE NOCASE").fetchall()

    def get_client(self, client_id: int) -> Optional[sqlite3.Row]:
        return self.conn.execute("SELECT * FROM clients WHERE id = ?", (client_id,)).fetchone()

    def delete_client(self, client_id: int) -> None:
        self.conn.execute("DELETE FROM clients WHERE id = ?", (client_id,))
        self.conn.commit()

    def add_visura(self, client_id: int, path: str, extracted: Dict[str, str], confronto: Dict[str, Tuple[str, str]]) -> None:
        self.conn.execute(
            "INSERT INTO visure (client_id, path, uploaded_at, extracted_json, confronto_json) VALUES (?, ?, ?, ?, ?)",
            (client_id, path, now_iso(), json.dumps(extracted, ensure_ascii=False), json.dumps(confronto, ensure_ascii=False)),
        )
        self.conn.commit()

    def last_visura_data(self, client_id: int) -> Dict[str, str]:
        row = self.conn.execute(
            "SELECT extracted_json FROM visure WHERE client_id = ? ORDER BY id DESC LIMIT 1",
            (client_id,),
        ).fetchone()
        if not row or not row["extracted_json"]:
            return {}
        try:
            return json.loads(row["extracted_json"])
        except Exception:
            return {}

    def get_visure(self, client_id: int) -> List[sqlite3.Row]:
        return self.conn.execute("SELECT * FROM visure WHERE client_id = ? ORDER BY id DESC", (client_id,)).fetchall()

    def save_mandato(self, data: Dict[str, str], mandato_id: Optional[int] = None) -> int:
        clean = {field: clean_inline(data.get(field, "")) for field in MANDATO_FIELDS}
        clean["note"] = normalize_space(data.get("note", ""))
        clean["client_id"] = str(data.get("client_id", ""))
        if mandato_id:
            cols = ", ".join(f"{field} = ?" for field in MANDATO_FIELDS)
            vals = [clean[field] for field in MANDATO_FIELDS] + [now_iso(), mandato_id]
            self.conn.execute(f"UPDATE mandati SET {cols}, updated_at = ? WHERE id = ?", vals)
            self.conn.commit()
            return int(mandato_id)
        vals = [now_iso(), now_iso()] + [clean[field] for field in MANDATO_FIELDS]
        placeholders = ", ".join("?" for _ in vals)
        fields = ", ".join(["created_at", "updated_at"] + MANDATO_FIELDS)
        cur = self.conn.execute(f"INSERT INTO mandati ({fields}) VALUES ({placeholders})", vals)
        self.conn.commit()
        return int(cur.lastrowid)

    def update_mandato_paths(self, mandato_id: int, docx_path: str = "", pdf_path: str = "") -> None:
        self.conn.execute(
            "UPDATE mandati SET docx_path = COALESCE(NULLIF(?, ''), docx_path), pdf_path = COALESCE(NULLIF(?, ''), pdf_path), updated_at = ? WHERE id = ?",
            (docx_path, pdf_path, now_iso(), mandato_id),
        )
        self.conn.commit()

    def get_mandati(self) -> List[sqlite3.Row]:
        return self.conn.execute(
            """
            SELECT m.*, c.denominazione AS cliente
            FROM mandati m
            LEFT JOIN clients c ON c.id = m.client_id
            ORDER BY m.id DESC
            """
        ).fetchall()

    def get_mandato(self, mandato_id: int) -> Optional[sqlite3.Row]:
        return self.conn.execute("SELECT * FROM mandati WHERE id = ?", (mandato_id,)).fetchone()


# -----------------------------------------------------------------------------
# Lettura visura PDF con riconoscimento avanzato
# -----------------------------------------------------------------------------

CF_PERSON_RE = re.compile(r"\b[A-Z]{6}[0-9LMNPQRSTUV]{2}[A-Z][0-9LMNPQRSTUV]{2}[A-Z][0-9LMNPQRSTUV]{3}[A-Z]\b", re.I)
EMAIL_RE = re.compile(r"\b[A-Z0-9._%+\-]+@[A-Z0-9.\-]+\.[A-Z]{2,}\b", re.I)
PIVA_RE = re.compile(r"\b\d{11}\b")
DATE_RE = re.compile(r"\b\d{1,2}[./-]\d{1,2}[./-]\d{2,4}\b")
CORP_FORM_RE = re.compile(
    r"\b(S\.?\s*R\.?\s*L\.?|SRL|S\.?\s*P\.?\s*A\.?|SPA|S\.?\s*A\.?\s*S\.?|SAS|S\.?\s*N\.?\s*C\.?|SNC|S\.?R\.?L\.?S\.?|SRLS|COOPERATIVA|CONSORZIO|SOCIETA')\b",
    re.I,
)
STOP_LABELS = [
    "domicilio digitale", "pec", "partita iva", "codice fiscale", "numero rea", "registro imprese",
    "forma giuridica", "data atto", "data iscrizione", "amministratore", "attivita", "capitale sociale",
    "addetti", "soci", "titolari", "unita locali", "bilanci", "statuto", "sede operativa", "sede legale",
]


def extract_pdf_text(pdf_path: str) -> str:
    """Estrae testo da PDF, comprese tabelle, con fallback su pypdf/PyPDF2."""
    chunks: List[str] = []
    try:
        import pdfplumber  # type: ignore

        with pdfplumber.open(pdf_path) as pdf:
            for page in pdf.pages:
                text = page.extract_text(x_tolerance=1, y_tolerance=3) or ""
                if text:
                    chunks.append(text)
                try:
                    tables = page.extract_tables() or []
                    for table in tables:
                        for row in table:
                            cells = [clean_inline(c) for c in row if clean_inline(c)]
                            if cells:
                                chunks.append(" | ".join(cells))
                except Exception:
                    pass
    except Exception:
        pass

    if not "\n".join(chunks).strip():
        for module_name in ("pypdf", "PyPDF2"):
            try:
                mod = __import__(module_name)
                reader = mod.PdfReader(pdf_path)
                for page in reader.pages:
                    chunks.append(page.extract_text() or "")
                break
            except Exception:
                continue

    text = "\n".join(chunks)
    # Normalizza righe senza perdere struttura delle tabelle
    text = text.replace("\r", "\n")
    text = re.sub(r"[ \t]+", " ", text)
    text = re.sub(r"\n{3,}", "\n\n", text)
    return text.strip()


def lines_from_text(text: str) -> List[str]:
    lines = []
    for raw in text.splitlines():
        line = clean_inline(raw)
        if line:
            lines.append(line)
    return lines


def value_after_label(lines: Sequence[str], labels: Sequence[str], max_lines: int = 3, stop_labels: Sequence[str] = STOP_LABELS) -> str:
    labels_simple = [simple(label) for label in labels]
    stop_simple = [simple(label) for label in stop_labels]
    for idx, line in enumerate(lines):
        sline = simple(line)
        if any(label in sline for label in labels_simple):
            # Inline: label : valore oppure label | valore
            value = line
            for label in labels:
                pattern = re.compile(re.escape(label), re.I)
                value = pattern.sub("", value, count=1)
            value = clean_inline(value)
            # rimuove separatori iniziali
            value = re.sub(r"^[|:;\-]+", "", value).strip()
            parts = []
            if value and simple(value) not in labels_simple and not any(simple(value) == st for st in stop_simple):
                parts.append(value)
            for j in range(idx + 1, min(len(lines), idx + 1 + max_lines)):
                nxt = clean_inline(lines[j])
                snxt = simple(nxt)
                if not nxt:
                    continue
                if any(st in snxt for st in stop_simple):
                    break
                # evita di assorbire righe numeriche isolate o titoli se il valore e' gia' presente
                if parts and re.fullmatch(r"\d+", nxt):
                    break
                parts.append(nxt)
            joined = clean_inline(" ".join(parts))
            if joined:
                return joined
    return ""


def extract_identifier(text: str, labels: Sequence[str], prefer_person_cf: bool = False) -> str:
    # Estrae su finestre vicine all'etichetta, poi fallback globale.
    for label in labels:
        pattern = re.compile(rf"{label}\s*[:\-\|\.]*\s*([A-Z0-9]{{11,16}})", re.I)
        m = pattern.search(text)
        if m:
            val = m.group(1).upper()
            if prefer_person_cf and not CF_PERSON_RE.fullmatch(val):
                continue
            return val
    if prefer_person_cf:
        m = CF_PERSON_RE.search(text.upper())
        return m.group(0).upper() if m else ""
    # Prima prova PIVA numerica / CF impresa numerico
    m = PIVA_RE.search(text)
    return m.group(0) if m else ""


def extract_piva(text: str) -> str:
    patterns = [
        r"(?:partita\s+iva|p\.\s*iva|p\.iva|piva)\s*[:\-\|\.]*\s*(\d{11})",
        r"(?:c\.f\.\s*e\s*p\.iva|cf\s*/\s*piva|codice\s+fiscale\s+e\s+partita\s+iva)\s*[:\-\|\.]*\s*(\d{11})",
    ]
    for p in patterns:
        m = re.search(p, text, re.I)
        if m:
            return m.group(1)
    return ""


def extract_company_cf(text: str) -> str:
    patterns = [
        r"(?:codice\s+fiscale\s+e\s+n\.\s*iscr\.\s+al\s+registro\s+imprese|codice\s+fiscale|cod\.\s*fiscale|c\.f\.)\s*[:\-\|\.]*\s*([A-Z0-9]{11,16})",
        r"(?:registro\s+imprese)\s*[:\-\|\.]*\s*([A-Z0-9]{11,16})",
    ]
    for p in patterns:
        m = re.search(p, text, re.I)
        if m:
            val = m.group(1).upper()
            if not CF_PERSON_RE.fullmatch(val):
                return val
    return ""


def looks_like_company_name(line: str) -> bool:
    s = simple(line)
    if len(line) < 4 or len(line) > 90:
        return False
    banned = [
        "visura", "dati anagrafici", "camera di commercio", "codice fiscale", "partita iva",
        "registro imprese", "indirizzo", "sede legale", "domicilio digitale", "capitale sociale",
        "attivita", "documenti consultabili", "l'impresa in cifre", "qr code",
    ]
    if any(b in s for b in banned):
        return False
    return bool(CORP_FORM_RE.search(line)) or bool(re.search(r"\b(SRL|SPA|SAS|SNC|SRLS)\b", line, re.I))



def clean_company_candidate(value: str) -> str:
    text = normalize_space(value)
    text = re.sub(r"\bDATI\s+ANAGRAFICI\b.*$", "", text, flags=re.I)
    text = re.sub(r"\bCamera\s+di\s+Commercio.*$", "", text, flags=re.I)
    text = re.sub(r"\s{2,}", " ", text).strip(" :-|;,\n\t")
    return text

def extract_denominazione(lines: Sequence[str], text: str) -> str:
    """Estrae la denominazione anche se e' in riquadri, tabelle o nella sezione
    Informazioni costitutive. Mantiene il punto finale di forme come S.R.L.
    """
    raw_text = text.replace("\r", "\n")

    # 1) Caso esplicito: "Denominazione: HASHCOM S.R.L." anche in Informazioni costitutive.
    patterns = [
        r"(?:denominazione|denominazione\s+o\s+ragione\s+sociale)\s*[:\-\|]\s*([^\n]+)",
        r"(?:VISURA\s+ORDINARIA\s+SOCIETA['’]\s+DI\s+CAPITALE)\s*\n\s*([^\n]+)",
    ]
    for pat in patterns:
        for m in re.finditer(pat, raw_text, flags=re.I):
            cand = clean_company_candidate(m.group(1))
            if looks_like_company_name(cand):
                return upper_company(cand)

    # 2) Etichetta su una riga e valore sulla riga successiva.
    for idx, line in enumerate(lines):
        if any(k in simple(line) for k in ["denominazione", "ragione sociale"]):
            tail = re.sub(r".*?(denominazione|ragione\s+sociale)\s*[:\-\|]?", "", line, flags=re.I).strip()
            for cand in [tail] + list(lines[idx + 1 : idx + 4]):
                cand = clean_company_candidate(cand)
                if looks_like_company_name(cand):
                    return upper_company(cand)

    # 3) Dentro blocchi Informazioni costitutive / Dati anagrafici.
    anchors = ["informazioni costitutive", "informazioni di statuto", "dati anagrafici", "visura ordinaria"]
    for idx, line in enumerate(lines):
        if any(a in simple(line) for a in anchors):
            for cand in lines[idx : min(len(lines), idx + 12)]:
                cand = clean_company_candidate(cand)
                if looks_like_company_name(cand):
                    return upper_company(cand)

    # 4) Prima riga plausibile con forma societaria.
    for line in lines:
        cand = clean_company_candidate(line)
        if looks_like_company_name(cand):
            return upper_company(cand)

    # 5) Fallback regex su testo intero.
    m = re.search(r"\b([A-Z0-9&' .\-]{2,80}\s+(?:S\.?R\.?L\.?|SRL|S\.?P\.?A\.?|SPA|SAS|SNC|SRLS))\b", raw_text, re.I)
    return upper_company(clean_company_candidate(m.group(1))) if m else ""


def extract_emails(text: str) -> Tuple[str, str]:
    emails = []
    for m in EMAIL_RE.finditer(text):
        email = m.group(0).strip(".;,")
        if email.lower() not in [e.lower() for e in emails]:
            emails.append(email)
    pec = ""
    mail = ""
    for email in emails:
        low = email.lower()
        # PEC esplicita o dominio tipico
        start = max(0, text.lower().find(low) - 70)
        ctx = text.lower()[start : text.lower().find(low) + len(low) + 20]
        if "pec" in ctx or "legalmail" in low or "pec" in low:
            pec = email
            break
    for email in emails:
        if email != pec:
            mail = email
            break
    if not mail and emails:
        mail = emails[0]
    return mail, pec


def extract_phone(text: str) -> str:
    # Non usare Partita IVA/Codice fiscale come telefono. Se la visura non riporta un
    # campo telefonico esplicito, il campo resta vuoto e puo' essere compilato a mano.
    patterns = [
        r"(?:telefono|tel\.|tel|recapito\s+telefonico)\s*[:\-\|\.]*\s*((?:\+39\s*)?(?:\d[\s./-]*){7,14})",
    ]
    for p in patterns:
        m = re.search(p, text, re.I)
        if m:
            phone = re.sub(r"\s+", " ", m.group(1)).strip(" ./-")
            if len(re.sub(r"\D", "", phone)) >= 7:
                return phone
    return ""


def extract_year_from_dates(text: str) -> str:
    # Preferisce data atto di costituzione
    m = re.search(r"(?:data\s+atto\s+di\s+costituzione|data\s+costituzione)\s*[:\-\|\.]*\s*(\d{1,2}[./-]\d{1,2}[./-](\d{4}))", text, re.I)
    if m:
        return m.group(2)
    m = re.search(r"(?:data\s+iscrizione)\s*[:\-\|\.]*\s*(\d{1,2}[./-]\d{1,2}[./-](\d{4}))", text, re.I)
    return m.group(2) if m else ""


def extract_activity(lines: Sequence[str], text: str) -> Tuple[str, str]:
    code = ""
    for pattern in [
        r"(?:codice\s+ateco|codice\s+nace|ateco)\s*[:\-\|\.]*\s*([0-9]{1,2}(?:[.,][0-9]{1,2})?)",
        r"Codice:\s*([0-9]{1,2}(?:[.,][0-9]{1,2})?)\s*-",
    ]:
        m = re.search(pattern, text, re.I)
        if m:
            code = m.group(1).replace(",", ".")
            break

    candidates: List[str] = []
    pattern = r"Attivit[àa] prevalente\s+(.+?)(?=\n(?:Codice\s+ATECO|Codice\s+NACE|Attivit[àa]\s+import|Classificazione|L'IMPRESA|CERTIFICAZIONE|6\s+Attivit|Registro\s+Imprese)|$)"
    for m in re.finditer(pattern, text, re.I | re.S):
        cand = normalize_space(m.group(1).replace("\n", " "))
        cand = re.sub(r"\b(Addetti|Soci e titolari|Amministratori|Titolari di cariche|Sindaci).*$", "", cand, flags=re.I).strip()
        if cand and len(cand) > 8:
            candidates.append(cand)

    # Preferisce la descrizione della pagina dettagliata, di solito in maiuscolo e senza testo di riquadro affiancato.
    candidates = sorted(candidates, key=lambda c: ("Addetti" in c or "Soci" in c, -len(c)))
    activity = candidates[0] if candidates else ""
    if not activity:
        activity = value_after_label(
            lines,
            ["attivita prevalente", "attività prevalente", "attivita esercitata", "descrizione attivita", "settore attivita"],
            max_lines=4,
            stop_labels=["codice ateco", "codice nace", "contratto", "albi", "certificazione", "l'impresa", "capitale", "documenti"],
        )
    activity = re.sub(r"^(prevalente|attivita|attività)\s*", "", activity, flags=re.I).strip()
    return code, activity


def extract_sede_legale(lines: Sequence[str]) -> str:
    sede = value_after_label(
        lines,
        ["indirizzo sede legale", "sede legale", "sede legale/amministrativa"],
        max_lines=4,
        stop_labels=[
            "domicilio digitale", "pec", "partita iva", "numero rea", "codice fiscale", "registro imprese",
            "forma giuridica", "data atto", "data iscrizione", "amministratore", "sede operativa",
        ],
    )
    return clean_inline(sede)


def extract_sede_operativa(lines: Sequence[str]) -> str:
    sede = value_after_label(
        lines,
        ["sede operativa", "unita locale", "unità locale", "indirizzo unita locale", "indirizzo unità locale"],
        max_lines=4,
        stop_labels=["sede legale", "domicilio digitale", "pec", "partita iva", "numero rea", "attivita", "amministratore"],
    )
    return clean_inline(sede)


def person_name_from_text(fragment: str) -> str:
    frag = clean_inline(fragment)
    # Rimuove cariche e parole non anagrafiche
    frag = re.sub(r"\b(amministratore\s+unico|amministratore|legale\s+rappresentante|rappresentante\s+dell['’]?impresa|rappresentante|dell['’]?impresa|socio\s+unico|titolare|consigliere|presidente)\b", " ", frag, flags=re.I)
    frag = re.sub(r"\b(nato|nata|codice\s+fiscale|domicilio|residenza|residente|carica|data|durata|poteri).*", " ", frag, flags=re.I)
    frag = re.sub(r"[^A-ZÀÈÉÌÒÙ'\- ]", " ", frag.upper())
    frag = re.sub(r"\s+", " ", frag).strip()
    candidates = re.findall(r"\b([A-ZÀÈÉÌÒÙ][A-ZÀÈÉÌÒÙ'\-]{1,}(?:\s+[A-ZÀÈÉÌÒÙ][A-ZÀÈÉÌÒÙ'\-]{1,}){1,3})\b", frag)
    banned = {
        "DATI ANAGRAFICI", "ELENCO AMMINISTRATORI", "ORGANI AMMINISTRATIVI", "AMMINISTRATORE UNICO",
        "RAPPRESENTANTE IMPRESA", "RAPPRESENTANTE DELL", "SOCIETA CAPITALE", "VISURA ORDINARIA",
    }
    for cand in candidates:
        s = simple(cand).upper()
        if any(b in s for b in banned):
            continue
        if CORP_FORM_RE.search(cand):
            continue
        if len(cand.split()) >= 2:
            return title_person(cand)
    return ""


def extract_admin_block(lines: Sequence[str]) -> List[str]:
    # Priorita' alla sezione dettagliata "Elenco amministratori", per non confondere
    # il domicilio dell'amministratore con il "Domicilio digitale/PEC" della societa'.
    for i, line in enumerate(lines):
        if "elenco amministratori" in simple(line):
            end = min(len(lines), i + 80)
            for j in range(i + 1, min(len(lines), i + 100)):
                sj = simple(lines[j])
                if re.match(r"^\d+\s+attiv", sj) or "attivita, albi" in sj or "attivita albi" in sj:
                    end = j
                    break
            return list(lines[i:end])

    anchors = []
    for i, line in enumerate(lines):
        s = simple(line)
        if any(term in s for term in ["amministratore", "legale rappresentante", "rappresentante dell'impresa", "organi amministrativi"]):
            anchors.append(i)
    if not anchors:
        return list(lines)

    # Usa il primo blocco che contiene amministratore e dati anagrafici successivi,
    # ma taglia prima delle sezioni aziendali per evitare falsi domicili.
    start = max(0, anchors[0] - 3)
    end = min(len(lines), anchors[0] + 60)
    for idx in anchors[1:]:
        if idx < end + 20:
            end = min(len(lines), idx + 60)
    for j in range(start + 1, end):
        sj = simple(lines[j])
        if "domicilio digitale" in sj and j < anchors[0]:
            start = j + 1
        if re.match(r"^\d+\s+attiv", sj) or "l'impresa in cifre" in sj:
            end = j
            break
    return list(lines[start:end])


def extract_admin_details(lines: Sequence[str], text: str) -> Dict[str, str]:
    block_lines = extract_admin_block(lines)
    block = "\n".join(block_lines)
    block_simple = simple(block)

    cariche = []
    if "amministratore unico" in block_simple:
        cariche.append("Amministratore Unico")
    if "legale rappresentante" in block_simple:
        cariche.append("Legale rappresentante")
    if "rappresentante dell'impresa" in block_simple or "rappresentante dell impresa" in block_simple:
        cariche.append("Rappresentante dell'impresa")
    if not cariche and "amministratore" in block_simple:
        cariche.append("Amministratore")
    carica = ", ".join(dict.fromkeys(cariche))

    name = ""
    # Casi su una riga: "Amministratore Unico ZANARDELLI LUCA Rappresentante dell'impresa"
    for line in block_lines:
        s = simple(line)
        if any(term in s for term in ["amministratore", "legale rappresentante", "rappresentante dell'impresa"]):
            candidate = person_name_from_text(line)
            if candidate:
                name = candidate
                break
            # prova parti tabellari separate da |
            for part in re.split(r"\|", line):
                candidate = person_name_from_text(part)
                if candidate:
                    name = candidate
                    break
        if name:
            break
    # Casi su righe adiacenti: carica sulla prima, nome sulla seconda.
    if not name:
        for idx, line in enumerate(block_lines):
            if "amministratore" in simple(line):
                for nxt in block_lines[idx + 1 : idx + 5]:
                    candidate = person_name_from_text(nxt)
                    if candidate:
                        name = candidate
                        break
            if name:
                break
    # Fallback nel testo intero vicino a carica
    if not name:
        m = re.search(r"(?:amministratore\s+unico|legale\s+rappresentante)\s+([A-ZÀÈÉÌÒÙ'\- ]{5,60})", block, re.I)
        if m:
            name = person_name_from_text(m.group(1))

    # Codice fiscale persona: preferisce blocco amministratore
    cf_admin = ""
    m = CF_PERSON_RE.search(block.upper())
    if m:
        cf_admin = m.group(0).upper()
    else:
        # Cerca codice fiscale dopo il nome se possibile
        m = re.search(r"(?:codice\s+fiscale|c\.f\.)\s*[:\-\|\.]*\s*([A-Z0-9]{16})", block, re.I)
        if m and CF_PERSON_RE.fullmatch(m.group(1).upper()):
            cf_admin = m.group(1).upper()

    luogo_nascita = ""
    data_nascita = ""
    m = re.search(
        r"(?:nato|nata)\s+a\s+(.{2,80}?)\s+(?:il|in\s+data)\s+(\d{1,2}[./-]\d{1,2}[./-]\d{2,4})",
        block,
        re.I | re.S,
    )
    if m:
        luogo_nascita = clean_inline(re.sub(r"\n", " ", m.group(1)))
        luogo_nascita = re.sub(r"\b(codice\s+fiscale|domicilio|residenza).*$", "", luogo_nascita, flags=re.I).strip()
        data_nascita = m.group(2).replace(".", "/").replace("-", "/")
    else:
        luogo_nascita = value_after_label(block_lines, ["luogo nascita", "luogo di nascita"], max_lines=1, stop_labels=["data nascita", "codice fiscale", "domicilio"])
        data_nascita = value_after_label(block_lines, ["data nascita", "data di nascita"], max_lines=1, stop_labels=["codice fiscale", "domicilio", "residenza"])
        mdate = DATE_RE.search(data_nascita)
        data_nascita = mdate.group(0).replace(".", "/").replace("-", "/") if mdate else data_nascita

    residenza = ""
    # Domicilio/residenza in blocco, anche su piu' righe.
    for labels in (["residenza", "residente in"], ["domicilio"]):
        residenza = value_after_label(
            block_lines,
            labels,
            max_lines=4,
            stop_labels=["carica", "data nomina", "data atto", "durata", "poteri", "socio unico", "amministratore", "elenco", "codice fiscale", "nato a"],
        )
        if residenza:
            break
    residenza = clean_inline(residenza)

    # Se il nome e' vuoto ma c'e' CF personale, prova a trovare un nome vicino al CF.
    if not name and cf_admin:
        pos = block.upper().find(cf_admin)
        context = block[max(0, pos - 180) : pos + 20]
        name = person_name_from_text(context)

    full = build_admin_text({
        "amministratore_nome": name,
        "amministratore_carica": carica,
        "amministratore_luogo_nascita": luogo_nascita,
        "amministratore_data_nascita": data_nascita,
        "amministratore_residenza": residenza,
        "amministratore_codice_fiscale": cf_admin,
    })

    return {
        "amministratore_nome": name,
        "amministratore_carica": carica,
        "amministratore_luogo_nascita": luogo_nascita,
        "amministratore_data_nascita": data_nascita,
        "amministratore_residenza": residenza,
        "amministratore_codice_fiscale": cf_admin,
        "amministratore_dati_completi": full,
    }


def build_admin_text(data: Dict[str, Any]) -> str:
    nome = clean_inline(data.get("amministratore_nome", ""))
    carica = clean_inline(data.get("amministratore_carica", ""))
    luogo = clean_inline(data.get("amministratore_luogo_nascita", ""))
    data_n = clean_inline(data.get("amministratore_data_nascita", ""))
    residenza = clean_inline(data.get("amministratore_residenza", ""))
    cf = clean_inline(data.get("amministratore_codice_fiscale", ""))

    parts = []
    if nome:
        parts.append(nome)
    if carica:
        parts.append(carica)
    if luogo and data_n:
        parts.append(f"nato/a a {luogo} il {data_n}")
    elif luogo:
        parts.append(f"nato/a a {luogo}")
    elif data_n:
        parts.append(f"nato/a il {data_n}")
    if residenza:
        parts.append(f"residente/domiciliato in {residenza}")
    if cf:
        parts.append(f"codice fiscale {cf}")
    return dedupe_words("; ".join(parts))



def build_admin_intro_text(data: Dict[str, Any]) -> str:
    """Testo da inserire nella prima riga del mandato.

    La carica non viene ripetuta qui perche' nel modello Word segue gia' il testo
    "amministratore unico". In questo modo la parte iniziale resta uguale alla foto
    e contiene comunque nascita, domicilio/residenza e codice fiscale.
    """
    nome = clean_inline(data.get("amministratore_nome", ""))
    luogo = clean_inline(data.get("amministratore_luogo_nascita", ""))
    data_n = clean_inline(data.get("amministratore_data_nascita", ""))
    residenza = clean_inline(data.get("amministratore_residenza", ""))
    cf = clean_inline(data.get("amministratore_codice_fiscale", ""))
    parts = []
    if nome:
        parts.append(nome)
    if luogo and data_n:
        parts.append(f"nato a {luogo} il {data_n}")
    elif luogo:
        parts.append(f"nato a {luogo}")
    elif data_n:
        parts.append(f"nato il {data_n}")
    if residenza:
        parts.append(f"residente/domiciliato in {residenza}")
    if cf:
        parts.append(f"codice fiscale {cf}")
    return dedupe_words("; ".join(parts))

def build_company_text(data: Dict[str, Any]) -> str:
    parts = []
    mapping = [
        ("Denominazione", "denominazione"),
        ("Partita IVA", "partita_iva"),
        ("Codice fiscale", "codice_fiscale"),
        ("Sede legale", "sede_legale"),
        ("Sede operativa", "sede_operativa"),
        ("PEC", "pec"),
        ("Email", "mail_azienda"),
        ("Telefono", "telefono_azienda"),
        ("Codice attivita'/ATECO", "codice_ateco"),
        ("Descrizione attivita'", "settore_attivita"),
        ("Anno costituzione", "anno_costituzione"),
    ]
    for label, key in mapping:
        val = clean_inline(data.get(key, ""))
        if val:
            parts.append(f"{label}: {val}")
    return "; ".join(parts)


def parse_visura(pdf_path: str) -> Dict[str, str]:
    text = extract_pdf_text(pdf_path)
    lines = lines_from_text(text)
    mail, pec = extract_emails(text)
    codice_ateco, settore = extract_activity(lines, text)
    admin = extract_admin_details(lines, text)

    data = {
        "denominazione": extract_denominazione(lines, text),
        "partita_iva": extract_piva(text),
        "codice_fiscale": extract_company_cf(text),
        "sede_legale": extract_sede_legale(lines),
        "sede_operativa": extract_sede_operativa(lines),
        "anno_costituzione": extract_year_from_dates(text),
        "settore_attivita": settore,
        "codice_ateco": codice_ateco,
        "mail_azienda": mail,
        "telefono_azienda": extract_phone(text),
        "pec": pec,
    }
    data.update(admin)
    # Normalizzazione finale
    data["denominazione"] = upper_company(data.get("denominazione", ""))
    for key in data:
        data[key] = clean_inline(data.get(key, ""))
    if not data.get("amministratore_dati_completi"):
        data["amministratore_dati_completi"] = build_admin_text(data)
    return data


# -----------------------------------------------------------------------------
# Lettura report PDF con riconoscimento dati anagrafici societari
# -----------------------------------------------------------------------------

def extract_report_sede_legale(text: str, lines: Sequence[str]) -> str:
    """Estrae la sede legale dai report in formato anagrafica/tabella.

    Nei report Creditime il dato puo' apparire come:
    Sede: VIA ...
    25126 BRESCIA (BS)
    oppure in testa come "Sede Legale" seguito da due righe.
    """
    raw = text.replace("\r", "\n")
    patterns = [
        r"Sede\s*:\s*([^\n]+)\n\s*([0-9]{5}\s+[^\n]+)",
        r"Sede\s+Legale\s*\n\s*([^\n]+)\n\s*([0-9]{5}\s+[^\n]+)",
        r"Indirizzo\s*:\s*([^\n]+\b[0-9]{5}\b[^\n]+)",
    ]
    for pat in patterns:
        m = re.search(pat, raw, flags=re.I)
        if not m:
            continue
        if len(m.groups()) >= 2:
            value = f"{m.group(1)} {m.group(2)}"
        else:
            value = m.group(1)
        value = clean_inline(value)
        value = re.sub(r"\s+", " ", value).strip(" ,;:-")
        if value and not re.search(r"codice\s+ateco|descrizione\s+ateco", value, re.I):
            return value
    # Fallback: etichetta su righe separate.
    return clean_inline(value_after_label(lines, ["Sede"], max_lines=2, stop_labels=["forma giuridica", "stato attivita", "data costituzione"]))


def extract_report_activity(text: str) -> Tuple[str, str]:
    """Preferisce Codice/Descrizione ATECO del riquadro sedi legali, poi fallback su Attivita'."""
    code = ""
    desc = ""
    m = re.search(r"Codice\s+ATECO\s*:\s*([0-9]{1,2}(?:[.,][0-9]{1,2}(?:[.,][0-9]{1,2})?)?)", text, re.I)
    if m:
        code = m.group(1).replace(",", ".")
    m = re.search(r"Descrizione\s+ATECO\s*:\s*([^\n]+)", text, re.I)
    if m:
        desc = clean_inline(m.group(1))
    if not code:
        m = re.search(r"Attivit[àa]\s*:\s*([0-9]{1,3}(?:[./,][0-9]{1,3})?)", text, re.I)
        if m:
            code = m.group(1).replace(",", ".")
    if not desc:
        m = re.search(r"Attivit[àa]\s+svolta\s+normalizzata\s*:\s*([^\n]+)", text, re.I)
        if m:
            desc = clean_inline(m.group(1))
    return code, desc


def extract_report_admin_details(lines: Sequence[str], text: str) -> Dict[str, str]:
    """Estrae il primo amministratore/legale rappresentante dal report.

    Evita di prendere revisori o altri soggetti: considera valido il blocco solo
    se contiene una carica amministrativa (AMMINISTRATORE / LEGALE RAPPRESENTANTE).
    """
    raw = text.replace("\r", "\n")
    candidates: List[Dict[str, str]] = []

    # Sezione piu' ricca: Esponenti Cariche, con indirizzo/domicilio.
    start = raw.lower().find("esponenti cariche")
    if start >= 0:
        section = raw[start : raw.lower().find("vertici aziendali", start) if raw.lower().find("vertici aziendali", start) > start else start + 3000]
        person_pat = re.compile(
            r"(?P<name>[A-ZÀÈÉÌÒÙ'\- ]{5,80})\s*\n"
            r"Cod\.\s*Fiscale\s*:\s*(?P<cf>[A-Z0-9]{16})(?P<body>.*?)(?=\n[A-ZÀÈÉÌÒÙ'\- ]{5,80}\s*\nCod\.\s*Fiscale|\nVERTICI\s+AZIENDALI|$)",
            re.I | re.S,
        )
        for m in person_pat.finditer(section):
            body = m.group("body")
            role_m = re.search(r"\b(AMMINISTRATORE\s+UNICO|AMMINISTRATORE|LEGALE\s+RAPPRESENTANTE|RAPPRESENTANTE\s+LEGALE)\b", body, re.I)
            if not role_m:
                continue
            name = title_person(clean_inline(m.group("name")))
            cf = m.group("cf").upper()
            date_m = re.search(r"Nato\s+il\s*:\s*(\d{1,2}[./-]\d{1,2}[./-]\d{2,4})", body, re.I)
            place_m = re.search(r"\na\s+([^\n]+?)(?:\s+SOCIO\s+UNICO|\s*\(|\n)", body, re.I)
            luogo = clean_inline(place_m.group(1)) if place_m else ""
            indirizzo = ""
            b_lines = lines_from_text(body)
            for idx, ln in enumerate(b_lines):
                if "indirizzo" in simple(ln):
                    for nxt in b_lines[idx + 1 : idx + 6]:
                        sn = simple(nxt)
                        if re.search(r"\b(via|viale|corso|piazza|p.zza|pza|largo|strada|contrada)\b", sn) and not re.fullmatch(r"dal\s+\d{1,2}/\d{1,2}/\d{2,4}.*", sn):
                            indirizzo = clean_inline(nxt)
                            break
                    if indirizzo:
                        break
            candidates.append({
                "amministratore_nome": name,
                "amministratore_carica": title_person(role_m.group(1)),
                "amministratore_luogo_nascita": luogo,
                "amministratore_data_nascita": date_m.group(1).replace(".", "/").replace("-", "/") if date_m else "",
                "amministratore_residenza": indirizzo,
                "amministratore_codice_fiscale": cf,
            })

    # Fallback: sezione Cariche aziendali esponenti, spesso senza domicilio ma con nascita e CF.
    if not candidates:
        m = re.search(
            r"Cariche\s+aziendali\s+esponenti\s+([A-ZÀÈÉÌÒÙ'\- ]{5,80})\s+Nato\s+il\s*:\s*(\d{1,2}[./-]\d{1,2}[./-]\d{2,4})\s+a\s+([^\n]+?)\s*\((AMMINISTRATORE[^)]*|LEGALE\s+RAPPRESENTANTE[^)]*)\).*?Codice\s+Fiscale\s*:\s*([A-Z0-9]{16})",
            raw,
            re.I | re.S,
        )
        if m:
            candidates.append({
                "amministratore_nome": title_person(clean_inline(m.group(1))),
                "amministratore_carica": title_person(clean_inline(m.group(4))),
                "amministratore_luogo_nascita": clean_inline(m.group(3)),
                "amministratore_data_nascita": m.group(2).replace(".", "/").replace("-", "/"),
                "amministratore_residenza": "",
                "amministratore_codice_fiscale": m.group(5).upper(),
            })

    data = candidates[0] if candidates else extract_admin_details(lines, text)
    data["amministratore_dati_completi"] = build_admin_text(data)
    return data


def parse_report(pdf_path: str) -> Dict[str, str]:
    """Legge un report PDF in assenza della visura e compila gli stessi campi.

    Supporta report con anagrafica tabellare: denominazione, C.F./P.IVA, sede,
    ATECO, telefono, PEC e sezione esponenti/amministratore.
    """
    text = extract_pdf_text(pdf_path)
    lines = lines_from_text(text)

    # Base di fallback: riusa il motore visura, poi corregge i campi tipici dei report.
    data = parse_visura(pdf_path)

    codice_ateco, settore = extract_report_activity(text)
    mail, pec = extract_emails(text)

    report_data = {
        "denominazione": extract_denominazione(lines, text),
        "partita_iva": extract_piva(text),
        "codice_fiscale": extract_company_cf(text),
        "sede_legale": extract_report_sede_legale(text, lines),
        "anno_costituzione": extract_year_from_dates(text),
        "settore_attivita": settore,
        "codice_ateco": codice_ateco,
        "mail_azienda": "" if mail and pec and mail.lower() == pec.lower() else mail,
        "telefono_azienda": extract_phone(text),
        "pec": pec,
    }
    report_data.update(extract_report_admin_details(lines, text))

    for key, val in report_data.items():
        if val:
            data[key] = val

    # Normalizzazione finale
    data["denominazione"] = upper_company(data.get("denominazione", ""))
    for key in data:
        data[key] = clean_inline(data.get(key, ""))
    data["amministratore_dati_completi"] = build_admin_text(data)
    return data


def compare_data(old: Dict[str, str], new: Dict[str, str]) -> Dict[str, Tuple[str, str]]:
    diff: Dict[str, Tuple[str, str]] = {}
    for key, new_val in new.items():
        old_val = old.get(key, "")
        if clean_inline(old_val) != clean_inline(new_val):
            diff[key] = (clean_inline(old_val), clean_inline(new_val))
    return diff


# -----------------------------------------------------------------------------
# Generazione mandato da DOCX template originale
# -----------------------------------------------------------------------------

@dataclass
class Placeholder:
    name: str
    aliases: Sequence[str]
    value_getter: Any


PLACEHOLDER_DATE = "INSERIRE LA DATA"


def client_value(client: Dict[str, Any], key: str) -> str:
    return clean_inline(client.get(key, ""))


def piva_cf_text(client: Dict[str, Any]) -> str:
    """Testo fiscale da inserire nel mandato.

    Nel modello Word il segnaposto INSERIRE PARTITA IVA si trova subito dopo
    la dicitura "Partita IVA e C.F.". Per questo qui inseriamo prima P.IVA/C.F.
    e subito dopo aggiungiamo anche sede legale e PEC prese dall'anagrafica
    cliente, come richiesto per la prima pagina del mandato.
    """
    piva = re.sub(r"\D+", "", client_value(client, "partita_iva"))
    cf = client_value(client, "codice_fiscale").upper()
    sede = client_value(client, "sede_legale")
    pec = client_value(client, "pec")

    if piva and cf and piva != cf:
        base = f"{piva} - C.F. {cf}"
    else:
        base = piva or cf

    extra: List[str] = []
    if sede:
        extra.append(f"sede legale {sede}")
    if pec:
        extra.append(f"PEC {pec}")

    if base and extra:
        return base + ", " + ", ".join(extra)
    if extra:
        return ", ".join(extra)
    return base


def dati_societa_mandato(client: Dict[str, Any]) -> str:
    """Testo azienda per la prima pagina del mandato.

    Nel modello corrente la partita IVA/C.F. e' gia' subito dopo con il segnaposto
    INSERIRE PARTITA IVA. Qui quindi inseriamo i dati aziendali essenziali senza
    duplicare inutilmente quel dato.
    """
    denominazione = client_value(client, "denominazione")
    sede = client_value(client, "sede_legale")
    pec = client_value(client, "pec")
    tel = client_value(client, "telefono_azienda")
    codice = client_value(client, "codice_ateco")
    descrizione = client_value(client, "settore_attivita")

    parts: List[str] = []
    if denominazione:
        parts.append(denominazione)
    if sede:
        parts.append(f"con sede legale in {sede}")
    if pec:
        parts.append(f"PEC {pec}")
    if tel:
        parts.append(f"telefono {tel}")
    if codice and descrizione:
        parts.append(f"codice attivita' {codice} - {descrizione}")
    elif codice:
        parts.append(f"codice attivita' {codice}")
    elif descrizione:
        parts.append(descrizione)
    return ", ".join(parts) or denominazione


def replace_span_in_runs(paragraph: Any, start: int, end: int, replacement: str) -> None:
    """Sostituisce testo tra start/end mantenendo i run esterni del modello."""
    runs = paragraph.runs
    if not runs or start >= end:
        return
    mapping: List[Tuple[int, int]] = []
    for i, run in enumerate(runs):
        for j, _ch in enumerate(run.text):
            mapping.append((i, j))
    if end > len(mapping):
        return
    start_run_idx, start_off = mapping[start]
    end_run_idx, end_off = mapping[end - 1]
    start_run = runs[start_run_idx]
    end_run = runs[end_run_idx]
    prefix = start_run.text[:start_off]
    suffix = end_run.text[end_off + 1:]
    if start_run_idx == end_run_idx:
        start_run.text = prefix + replacement + suffix
    else:
        start_run.text = prefix + replacement
        for i in range(start_run_idx + 1, end_run_idx):
            runs[i].text = ""
        end_run.text = suffix


def find_first_placeholder(text: str, placeholders: Sequence[Placeholder]) -> Optional[Tuple[int, int, Placeholder, str]]:
    found: Optional[Tuple[int, int, Placeholder, str]] = None
    for ph in placeholders:
        for alias in ph.aliases:
            idx = text.find(alias)
            if idx < 0:
                continue
            current = (idx, idx + len(alias), ph, alias)
            if found is None or idx < found[0] or (idx == found[0] and len(alias) > len(found[3])):
                found = current
    return found


def replace_paragraph_placeholders(paragraph: Any, placeholders: Sequence[Placeholder]) -> int:
    count = 0
    while True:
        text = "".join(run.text for run in paragraph.runs)
        if not text:
            return count
        hit = find_first_placeholder(text, placeholders)
        if not hit:
            return count
        start, end, ph, _alias = hit
        replacement = clean_inline(ph.value_getter())
        replace_span_in_runs(paragraph, start, end, replacement)
        count += 1
        if count > 200:
            return count


def iter_cell_paragraphs(cell: Any) -> Iterable[Any]:
    for p in cell.paragraphs:
        yield p
    for table in cell.tables:
        for row in table.rows:
            for nested_cell in row.cells:
                yield from iter_cell_paragraphs(nested_cell)


def iter_paragraphs(document: Any) -> Iterable[Any]:
    for p in document.paragraphs:
        yield p
    for table in document.tables:
        for row in table.rows:
            for cell in row.cells:
                yield from iter_cell_paragraphs(cell)
    for section in document.sections:
        parts = [section.header, section.footer, section.first_page_header, section.first_page_footer]
        try:
            parts.extend([section.even_page_header, section.even_page_footer])
        except Exception:
            pass
        for part in parts:
            for p in part.paragraphs:
                yield p
            for table in part.tables:
                for row in table.rows:
                    for cell in row.cells:
                        yield from iter_cell_paragraphs(cell)


def extract_docx_text(docx_path: str) -> str:
    if Document is None:
        return ""
    doc = Document(str(docx_path))
    texts: List[str] = []
    for p in iter_paragraphs(doc):
        if p.text:
            texts.append(p.text)
    return "\n".join(texts)


def build_replacements(client: Dict[str, Any], mandato: Dict[str, Any]) -> Tuple[List[Placeholder], str, str]:
    # Prima pagina come da modello/foto: amministratore, denominazione societa' e P.IVA/C.F.
    admin_intro = build_admin_intro_text(client) or clean_inline(client.get("amministratore_dati_completi", "")) or build_admin_text(client)
    company_name = client_value(client, "denominazione")
    company_full = company_name
    piva_text = piva_cf_text(client)
    data = clean_inline(mandato.get("data_mandato", "")) or today_it()
    importo = clean_inline(mandato.get("importo_consulenza", ""))
    finanziamento = clean_inline(mandato.get("importo_finanziamento", ""))
    banca = clean_inline(mandato.get("banca", ""))
    descrizione = clean_inline(mandato.get("descrizione_compenso", ""))

    def company_value() -> str:
        return company_name

    placeholders = [
        Placeholder(
            "amministratore",
            [
                "INSERIRE DATI AMINISTRATORE",  # refuso presente nel modello allegato
                "INSERIRE DATI AMMINISTRATORE",
                "INSERIRE DATI ANAGRAFICI AMMINISTRATORE",
            ],
            lambda: admin_intro,
        ),
        Placeholder(
            "societa",
            [
                "INSERIRE DATI SOCIETA’",
                "INSERIRE DATI SOCIETA'",
                "INSERIRE DATI SOCIETA`",
                "INSERIRE DENOMINAZIONE AZIENDA",
            ],
            company_value,
        ),
        Placeholder("partita_iva", ["INSERIRE PARTITA IVA"], lambda: piva_text),
        Placeholder("data", [PLACEHOLDER_DATE], lambda: data),
        Placeholder(
            "pari_ad_importo",
            ["PARI ad importo", "PARI AD IMPORTO", "PARI al IMPORTO", "PARI AL IMPORTO"],
            lambda: f"PARI ad {importo}" if importo else "PARI ad",
        ),
        Placeholder("importo", ["IMPORTO"], lambda: importo),
        Placeholder("finanziamento", ["FINANZIAMENTO"], lambda: finanziamento),
        Placeholder("banca", ["BANCA"], lambda: banca),
        Placeholder("descrizione", ["INSERIRE DESCRIZIONE"], lambda: descrizione),
    ]
    return placeholders, company_full, company_name


def generate_mandato_docx(template_path: str, output_path: str, client: Dict[str, Any], mandato: Dict[str, Any]) -> str:
    """Compila il modello Word originale mantenendo grafica e contenuto.

    Il programma NON ricrea il mandato e NON usa ReportLab per impaginare il mandato.
    Sostituisce solo i segnaposto presenti nel file Mandato_vuoto.docx.
    """
    if Document is None:
        raise RuntimeError("Modulo python-docx non installato. Esegui: pip install python-docx")
    template = Path(template_path)
    if not template.exists():
        raise FileNotFoundError(f"Modello non trovato: {template}")

    doc = Document(str(template))
    placeholders, _company_full, _company_name = build_replacements(client, mandato)
    for paragraph in iter_paragraphs(doc):
        replace_paragraph_placeholders(paragraph, placeholders)

    # Fallback mirato: se il modello scrive 'PARI ad importo' con run spezzati
    # e la sostituzione completa non ha colpito, sostituiamo solo la parola dopo 'PARI ad'.
    importo = clean_inline(mandato.get("importo_consulenza", ""))
    if importo:
        for paragraph in iter_paragraphs(doc):
            full = "".join(run.text for run in paragraph.runs)
            m = re.search(r"PARI\s+ad\s+(importo)\b", full, flags=re.I)
            if m:
                replace_span_in_runs(paragraph, m.start(1), m.end(1), importo)
                break

    out = Path(output_path)
    out.parent.mkdir(parents=True, exist_ok=True)
    doc.save(str(out))
    return str(out)


def convert_docx_to_pdf(docx_path: str, out_dir: Optional[str] = None) -> str:
    """Esporta il DOCX compilato in PDF fedele al modello.

    Per avere la stessa grafica del Word allegato serve un motore di impaginazione:
    Microsoft Word su Windows oppure LibreOffice/soffice. Se nessuno e' disponibile,
    ritorna stringa vuota e il DOCX resta comunque salvato.
    """
    source = Path(docx_path).resolve()
    out = Path(out_dir).resolve() if out_dir else source.parent
    out.mkdir(parents=True, exist_ok=True)
    pdf_path = out / (source.stem + ".pdf")

    if sys.platform.startswith("win"):
        word = None
        try:
            import win32com.client  # type: ignore
            word = win32com.client.Dispatch("Word.Application")
            word.Visible = False
            doc = word.Documents.Open(str(source))
            doc.ExportAsFixedFormat(str(pdf_path), 17)
            doc.Close(False)
            word.Quit()
            if pdf_path.exists() and pdf_path.stat().st_size > 0:
                return str(pdf_path)
        except Exception:
            try:
                if word is not None:
                    word.Quit()
            except Exception:
                pass

    soffice = shutil.which("soffice") or shutil.which("libreoffice")
    if soffice:
        try:
            with tempfile.TemporaryDirectory() as tmpdir:
                cmd = [soffice, "--headless", "--convert-to", "pdf", "--outdir", tmpdir, str(source)]
                subprocess.run(cmd, check=True, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True, timeout=120)
                generated = Path(tmpdir) / (source.stem + ".pdf")
                if generated.exists() and generated.stat().st_size > 0:
                    shutil.copy2(generated, pdf_path)
                    if pdf_path.exists() and pdf_path.stat().st_size > 0:
                        return str(pdf_path)
        except Exception:
            return ""

    return ""


