class ScrollFrame(ttk.Frame):
    def __init__(self, parent: tk.Widget):
        super().__init__(parent)
        self.canvas = tk.Canvas(self, highlightthickness=0)
        self.v_scroll = ttk.Scrollbar(self, orient="vertical", command=self.canvas.yview)
        self.inner = ttk.Frame(self.canvas)
        self.inner.bind("<Configure>", lambda e: self.canvas.configure(scrollregion=self.canvas.bbox("all")))
        self.canvas.create_window((0, 0), window=self.inner, anchor="nw")
        self.canvas.configure(yscrollcommand=self.v_scroll.set)
        self.canvas.pack(side="left", fill="both", expand=True)
        self.v_scroll.pack(side="right", fill="y")
        self.canvas.bind_all("<MouseWheel>", self._on_mousewheel)

    def _on_mousewheel(self, event: Any) -> None:
        try:
            self.canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")
        except Exception:
            pass


class FinancePlusApp(tk.Tk):
    def __init__(self) -> None:
        super().__init__()
        self.title(APP_NAME)
        self.geometry("1180x760")
        self.minsize(980, 680)
        self.db = Database()
        self.current_client_id: Optional[int] = None
        self.current_mandato_id: Optional[int] = None
        self.pending_visura_path = ""
        self.pending_visura_data: Dict[str, str] = {}
        self.current_generated_docx = ""
        self.current_generated_pdf = ""
        self.logo_image = None
        self.client_entries: Dict[str, Any] = {}
        self.mandato_entries: Dict[str, Any] = {}
        self.client_combo_map: Dict[str, int] = {}
        self.style = ttk.Style(self)
        self.configure_style()
        self.show_home()

    def configure_style(self) -> None:
        try:
            self.style.theme_use("clam")
        except Exception:
            pass
        self.style.configure("Title.TLabel", font=("Arial", 20, "bold"))
        self.style.configure("Subtitle.TLabel", font=("Arial", 11))
        self.style.configure("Big.TButton", font=("Arial", 13, "bold"), padding=12)
        self.style.configure("Accent.TButton", font=("Arial", 10, "bold"), padding=8)

    def clear(self) -> None:
        for child in self.winfo_children():
            child.destroy()

    def get_logo_image(self) -> Optional[tk.PhotoImage]:
        if self.logo_image is not None:
            return self.logo_image
        try:
            if not LOGO_FILE.exists():
                return None
            img = tk.PhotoImage(file=str(LOGO_FILE))
            # Riduce il logo senza dipendenze esterne. Mantiene un riferimento in self.
            factor = max(1, int(max(img.width() / 118, img.height() / 118)))
            if factor > 1:
                img = img.subsample(factor, factor)
            self.logo_image = img
            return self.logo_image
        except Exception:
            return None

    def header(self, parent: tk.Widget, title: str, subtitle: str = "") -> ttk.Frame:
        frame = ttk.Frame(parent, padding=(18, 12))
        frame.pack(fill="x")
        logo = self.get_logo_image()
        if logo is not None:
            ttk.Label(frame, image=logo).pack(side="left", padx=(0, 14))
            texts = ttk.Frame(frame)
            texts.pack(side="left", fill="x", expand=True)
        else:
            texts = frame
        ttk.Label(texts, text=title, style="Title.TLabel").pack(anchor="w")
        if subtitle:
            ttk.Label(texts, text=subtitle, style="Subtitle.TLabel").pack(anchor="w", pady=(2, 0))
        return frame

    def show_home(self) -> None:
        self.clear()
        self.header(self, "FinancePlus.Tech - Gestionale Mandato", "Clienti, visure camerali, mandati e report - salvataggio offline")
        body = ttk.Frame(self, padding=30)
        body.pack(fill="both", expand=True)
        buttons = [
            ("Nuovo Cliente", self.show_new_client),
            ("Mandato", self.show_mandato_menu),
            ("Elenco Clienti", self.show_clients_list),
            ("Report", self.show_report),
        ]
        for idx, (label, cmd) in enumerate(buttons):
            btn = ttk.Button(body, text=label, style="Big.TButton", command=cmd)
            btn.grid(row=idx // 2, column=idx % 2, sticky="nsew", padx=18, pady=18, ipadx=20, ipady=30)
        body.columnconfigure(0, weight=1)
        body.columnconfigure(1, weight=1)
        body.rowconfigure(0, weight=1)
        body.rowconfigure(1, weight=1)
        footer = ttk.Frame(self, padding=(18, 6))
        footer.pack(fill="x")
        ttk.Label(footer, text=f"Archivio: {DATA_DIR}").pack(side="left")

    # ------------------------------ Nuovo Cliente ---------------------------

    def show_new_client(self, client_id: Optional[int] = None) -> None:
        self.clear()
        self.current_client_id = client_id
        self.pending_visura_path = ""
        self.pending_visura_data = {}
        self.header(
            self,
            "Nuovo Cliente" if not client_id else "Modifica Cliente",
            "Inserisci visura camerale o compila/modifica manualmente i campi prima di salvare.",
        )
        top = ttk.Frame(self, padding=(18, 0, 18, 10))
        top.pack(fill="x")
        ttk.Button(top, text="Inserisci Visura Camerale", style="Accent.TButton", command=self.insert_visura_cliente).pack(side="left", padx=(0, 8))
        ttk.Button(top, text="Inserisci Report", style="Accent.TButton", command=self.insert_report_cliente).pack(side="left", padx=8)
        ttk.Button(top, text="Salva", style="Accent.TButton", command=self.save_client_from_form).pack(side="left", padx=8)
        ttk.Button(top, text="Storico Visure", command=self.show_visure_history_current).pack(side="left", padx=8)
        ttk.Button(top, text="Indietro", command=self.show_home).pack(side="right")

        scroll = ScrollFrame(self)
        scroll.pack(fill="both", expand=True, padx=18, pady=(0, 18))
        form = scroll.inner
        self.client_entries = {}

        groups = [
            ("Dati societa'", [
                ("Denominazione", "denominazione"),
                ("Partita IVA", "partita_iva"),
                ("Codice fiscale azienda", "codice_fiscale"),
                ("Sede legale", "sede_legale"),
                ("Sede operativa", "sede_operativa"),
                ("Anno costituzione", "anno_costituzione"),
                ("Settore attivita' / descrizione", "settore_attivita"),
                ("Codice ATECO / codice attivita'", "codice_ateco"),
                ("Mail azienda", "mail_azienda"),
                ("Telefono azienda", "telefono_azienda"),
                ("PEC", "pec"),
            ]),
            ("Dati amministratore / legale rappresentante", [
                ("Nome e cognome", "amministratore_nome"),
                ("Ruolo / carica", "amministratore_carica"),
                ("Luogo nascita", "amministratore_luogo_nascita"),
                ("Data nascita", "amministratore_data_nascita"),
                ("Residenza / domicilio", "amministratore_residenza"),
                ("Codice fiscale", "amministratore_codice_fiscale"),
            ]),
        ]
        row = 0
        for title, fields in groups:
            ttk.Label(form, text=title, font=("Arial", 12, "bold")).grid(row=row, column=0, columnspan=4, sticky="w", pady=(14, 6))
            row += 1
            for label, key in fields:
                ttk.Label(form, text=label).grid(row=row, column=0, sticky="w", padx=(0, 12), pady=4)
                ent = ttk.Entry(form, width=90)
                ent.grid(row=row, column=1, columnspan=3, sticky="ew", pady=4)
                self.client_entries[key] = ent
                row += 1

        ttk.Label(form, text="Dati amministratore completi inseriti nel mandato", font=("Arial", 12, "bold")).grid(row=row, column=0, columnspan=4, sticky="w", pady=(16, 6))
        row += 1
        admin_text = tk.Text(form, height=4, width=90, wrap="word")
        admin_text.grid(row=row, column=0, columnspan=4, sticky="ew", pady=4)
        self.client_entries["amministratore_dati_completi"] = admin_text
        row += 1
        ttk.Button(form, text="Ricompila dati amministratore completi", command=self.refresh_admin_full_text).grid(row=row, column=0, columnspan=2, sticky="w", pady=(4, 12))
        row += 1

        ttk.Label(form, text="Report allegato").grid(row=row, column=0, sticky="w", padx=(0, 12), pady=4)
        report = ttk.Entry(form, width=90)
        report.grid(row=row, column=1, columnspan=3, sticky="ew", pady=4)
        self.client_entries["report_path"] = report
        form.columnconfigure(1, weight=1)

        if client_id:
            row_data = self.db.get_client(client_id)
            if row_data:
                self.fill_client_form(dict(row_data))

    def fill_client_form(self, data: Dict[str, Any]) -> None:
        for key, widget in self.client_entries.items():
            value = data.get(key, "") or ""
            if isinstance(widget, tk.Text):
                widget.delete("1.0", "end")
                widget.insert("1.0", value)
            else:
                widget.delete(0, "end")
                widget.insert(0, value)

    def collect_client_form(self) -> Dict[str, str]:
        data: Dict[str, str] = {}
        for key, widget in self.client_entries.items():
            if isinstance(widget, tk.Text):
                data[key] = widget.get("1.0", "end").strip()
            else:
                data[key] = widget.get().strip()
        if not data.get("amministratore_dati_completi"):
            data["amministratore_dati_completi"] = build_admin_text(data)
        return data

    def refresh_admin_full_text(self) -> None:
        data = self.collect_client_form()
        full = build_admin_text(data)
        widget = self.client_entries.get("amministratore_dati_completi")
        if isinstance(widget, tk.Text):
            widget.delete("1.0", "end")
            widget.insert("1.0", full)

    def insert_report_cliente(self) -> None:
        path = filedialog.askopenfilename(title="Seleziona report PDF", filetypes=[("PDF", "*.pdf"), ("Tutti i file", "*.*")])
        if not path:
            return
        try:
            data = parse_report(path)
        except Exception as exc:
            messagebox.showerror(APP_NAME, f"Errore lettura report:\n{exc}")
            return
        copied = copy_to_folder(path, REPORT_DIR, safe_filename(data.get("denominazione", "report")) or "report")
        data["report_path"] = copied or path

        # Riempie i campi trovati dal report come accade con la visura.
        current = self.collect_client_form()
        merged = current.copy()
        for key, val in data.items():
            if val:
                merged[key] = val
        merged["amministratore_dati_completi"] = data.get("amministratore_dati_completi") or build_admin_text(merged)
        self.fill_client_form(merged)

        missing_admin = [
            label for label, key in [
                ("nome", "amministratore_nome"),
                ("carica", "amministratore_carica"),
                ("codice fiscale", "amministratore_codice_fiscale"),
                ("residenza/domicilio", "amministratore_residenza"),
            ] if not merged.get(key)
        ]
        if missing_admin:
            msg = "Report caricato. Controllare i dati estratti.\n\nDati amministratore ancora mancanti: " + ", ".join(missing_admin)
        else:
            msg = "Report caricato. I dati societari e dell'amministratore sono stati compilati. Controllare e salvare."
        messagebox.showinfo(APP_NAME, msg)

    def insert_visura_cliente(self) -> None:
        path = filedialog.askopenfilename(title="Seleziona visura camerale PDF", filetypes=[("PDF", "*.pdf"), ("Tutti i file", "*.*")])
        if not path:
            return
        try:
            data = parse_visura(path)
        except Exception as exc:
            messagebox.showerror(APP_NAME, f"Errore lettura visura:\n{exc}")
            return
        self.pending_visura_path = path
        self.pending_visura_data = data
        # Riempie solo i campi trovati, senza cancellare eventuali dati manuali migliori.
        current = self.collect_client_form()
        merged = current.copy()
        for key, val in data.items():
            if val:
                merged[key] = val
        if not merged.get("amministratore_dati_completi") or data.get("amministratore_dati_completi"):
            merged["amministratore_dati_completi"] = data.get("amministratore_dati_completi") or build_admin_text(merged)
        self.fill_client_form(merged)
        missing_admin = [
            label for label, key in [
                ("nome", "amministratore_nome"),
                ("carica", "amministratore_carica"),
                ("codice fiscale", "amministratore_codice_fiscale"),
                ("residenza/domicilio", "amministratore_residenza"),
            ] if not merged.get(key)
        ]
        if missing_admin:
            msg = "Visura caricata. Controllare i dati estratti.\n\nDati amministratore ancora mancanti: " + ", ".join(missing_admin)
        else:
            msg = "Visura caricata. I dati dell'amministratore sono stati compilati. Controllare e salvare."
        messagebox.showinfo(APP_NAME, msg)

    def save_client_from_form(self) -> None:
        data = self.collect_client_form()
        if not data.get("denominazione"):
            messagebox.showwarning(APP_NAME, "Inserire almeno la denominazione del cliente.")
            return
        client_id = self.db.save_client(data, self.current_client_id)
        self.current_client_id = client_id
        if self.pending_visura_path:
            copied = copy_to_folder(self.pending_visura_path, VISURE_DIR, safe_filename(data.get("denominazione", "cliente")))
            old = self.db.last_visura_data(client_id)
            confronto = compare_data(old, self.pending_visura_data) if old else {}
            self.db.add_visura(client_id, copied or self.pending_visura_path, self.pending_visura_data, confronto)
            self.pending_visura_path = ""
            self.pending_visura_data = {}
        messagebox.showinfo(APP_NAME, "Cliente salvato correttamente.")

    def show_visure_history_current(self) -> None:
        if not self.current_client_id:
            messagebox.showwarning(APP_NAME, "Salva prima il cliente per vedere lo storico visure.")
            return
        self.show_visure_history(self.current_client_id)

    def show_visure_history(self, client_id: int) -> None:
        win = tk.Toplevel(self)
        win.title("Storico visure")
        win.geometry("900x520")
        cols = ("data", "file", "confronto")
        tree = ttk.Treeview(win, columns=cols, show="headings")
        tree.heading("data", text="Data")
        tree.heading("file", text="File")
        tree.heading("confronto", text="Variazioni")
        tree.column("data", width=150)
        tree.column("file", width=380)
        tree.column("confronto", width=320)
        tree.pack(fill="both", expand=True, padx=12, pady=12)
        rows = self.db.get_visure(client_id)
        paths: Dict[str, str] = {}
        for row in rows:
            diff = ""
            try:
                d = json.loads(row["confronto_json"] or "{}")
                diff = ", ".join(d.keys()) if d else "prima visura / nessuna variazione"
            except Exception:
                diff = ""
            iid = str(row["id"])
            paths[iid] = row["path"]
            tree.insert("", "end", iid=iid, values=(row["uploaded_at"], Path(row["path"] or "").name, diff))

        def open_selected() -> None:
            sel = tree.selection()
            if sel:
                open_file(paths.get(sel[0], ""))

        ttk.Button(win, text="Apri visura selezionata", command=open_selected).pack(pady=(0, 12))

    # ------------------------------ Elenco Clienti --------------------------

    def show_clients_list(self) -> None:
        self.clear()
        self.header(self, "Elenco Clienti", "Doppio clic su un cliente per modificarlo.")
        top = ttk.Frame(self, padding=(18, 0, 18, 10))
        top.pack(fill="x")
        ttk.Button(top, text="Nuovo Cliente", command=lambda: self.show_new_client(None)).pack(side="left")
        ttk.Button(top, text="Indietro", command=self.show_home).pack(side="right")

        cols = ("id", "denominazione", "piva", "admin", "pec", "telefono")
        tree = ttk.Treeview(self, columns=cols, show="headings")
        headers = {
            "id": "ID",
            "denominazione": "Denominazione",
            "piva": "Partita IVA",
            "admin": "Amministratore",
            "pec": "PEC",
            "telefono": "Telefono",
        }
        widths = {"id": 60, "denominazione": 280, "piva": 120, "admin": 210, "pec": 220, "telefono": 120}
        for col in cols:
            tree.heading(col, text=headers[col])
            tree.column(col, width=widths[col])
        tree.pack(fill="both", expand=True, padx=18, pady=(0, 18))
        for row in self.db.get_clients():
            tree.insert("", "end", iid=str(row["id"]), values=(row["id"], row["denominazione"], row["partita_iva"], row["amministratore_nome"], row["pec"], row["telefono_azienda"]))
        tree.bind("<Double-1>", lambda e: self._open_client_from_tree(tree))

    def _open_client_from_tree(self, tree: ttk.Treeview) -> None:
        sel = tree.selection()
        if sel:
            self.show_new_client(int(sel[0]))

    # ------------------------------ Mandato ---------------------------------

    def show_mandato_menu(self) -> None:
        self.clear()
        self.header(self, "Mandato", "Nuovo mandato, elenco mandati, dati finanziamento e Mandato Definitivo.")
        body = ttk.Frame(self, padding=30)
        body.pack(fill="both", expand=True)
        buttons = [
            ("Nuovo Mandato", lambda: self.show_new_mandato(None)),
            ("Elenco Mandati", self.show_mandati_list),
            ("Dati Finanziamento", self.show_financing_window),
            ("Genera Mandato Definitivo", lambda: self.show_new_mandato(None)),
        ]
        for idx, (label, cmd) in enumerate(buttons):
            ttk.Button(body, text=label, style="Big.TButton", command=cmd).grid(row=idx // 2, column=idx % 2, sticky="nsew", padx=18, pady=18, ipadx=20, ipady=30)
        body.columnconfigure(0, weight=1)
        body.columnconfigure(1, weight=1)
        body.rowconfigure(0, weight=1)
        body.rowconfigure(1, weight=1)
        ttk.Button(self, text="Indietro", command=self.show_home).pack(pady=(0, 18))

    def refresh_client_combo(self) -> List[str]:
        clients = self.db.get_clients()
        self.client_combo_map = {}
        values = []
        for c in clients:
            label = f"{c['id']} - {c['denominazione']}"
            values.append(label)
            self.client_combo_map[label] = int(c["id"])
        return values

    def show_new_mandato(self, mandato_id: Optional[int] = None) -> None:
        self.clear()
        self.current_mandato_id = mandato_id
        self.current_generated_docx = ""
        self.current_generated_pdf = ""
        self.header(
            self,
            "Nuovo Mandato" if not mandato_id else "Modifica Mandato",
            "Scegli il cliente: i dati societari e dell'amministratore vengono caricati automaticamente.",
        )
        top = ttk.Frame(self, padding=(18, 0, 18, 10))
        top.pack(fill="x")
        ttk.Button(top, text="Inserisci visura", command=self.insert_visura_from_mandato).pack(side="left", padx=(0, 8))
        ttk.Button(top, text="Inserisci report", command=self.insert_report_from_mandato).pack(side="left", padx=(0, 8))
        ttk.Button(top, text="Dati Finanziamento", style="Accent.TButton", command=self.show_financing_window).pack(side="left", padx=8)
        ttk.Button(top, text="Salva Mandato", style="Accent.TButton", command=self.save_mandato_from_form).pack(side="left", padx=8)
        ttk.Button(top, text="Genera Mandato Definitivo", style="Accent.TButton", command=self.generate_definitive_mandato).pack(side="left", padx=8)
        ttk.Button(top, text="Anteprima PDF", command=self.preview_pdf).pack(side="left", padx=8)
        ttk.Button(top, text="Salva PDF", command=self.save_pdf_as).pack(side="left", padx=8)
        ttk.Button(top, text="Stampa", command=self.print_current_pdf).pack(side="left", padx=8)
        ttk.Button(top, text="Indietro", command=self.show_mandato_menu).pack(side="right")

        scroll = ScrollFrame(self)
        scroll.pack(fill="both", expand=True, padx=18, pady=(0, 18))
        form = scroll.inner
        self.mandato_entries = {}
        row = 0
        ttk.Label(form, text="Cliente").grid(row=row, column=0, sticky="w", padx=(0, 12), pady=5)
        combo = ttk.Combobox(form, values=self.refresh_client_combo(), width=88, state="readonly")
        combo.grid(row=row, column=1, columnspan=3, sticky="ew", pady=5)
        combo.bind("<<ComboboxSelected>>", lambda e: self.load_client_summary())
        self.mandato_entries["cliente_combo"] = combo
        row += 1
        summary = tk.Text(form, height=8, width=92, wrap="word", state="disabled")
        summary.grid(row=row, column=0, columnspan=4, sticky="ew", pady=(5, 15))
        self.mandato_entries["client_summary"] = summary
        row += 1

        fields = [
            ("Data mandato", "data_mandato", today_it()),
            ("Stato", "stato", ""),
            ("Responsabile", "responsabile", ""),
            ("Oggetto mandato", "oggetto", "Consulenza finanziaria"),
            ("Importo finanziamento", "importo_finanziamento", ""),
            ("Percentuale", "percentuale", ""),
            ("Importo consulenza", "importo_consulenza", ""),
            ("Banca / Istituto", "banca", ""),
            ("Descrizione compenso", "descrizione_compenso", ""),
            ("Luogo", "luogo", "Casagiove"),
            ("File allegato", "allegato_path", ""),
        ]
        for label, key, default in fields:
            ttk.Label(form, text=label).grid(row=row, column=0, sticky="w", padx=(0, 12), pady=4)
            ent = ttk.Entry(form, width=90)
            ent.grid(row=row, column=1, columnspan=2, sticky="ew", pady=4)
            ent.insert(0, default)
            self.mandato_entries[key] = ent
            if key == "allegato_path":
                ttk.Button(form, text="Sfoglia", command=self.choose_mandato_attachment).grid(row=row, column=3, sticky="w", padx=8)
            row += 1
        ttk.Label(form, text="Note").grid(row=row, column=0, sticky="nw", padx=(0, 12), pady=4)
        note = tk.Text(form, height=5, width=90, wrap="word")
        note.grid(row=row, column=1, columnspan=3, sticky="ew", pady=4)
        self.mandato_entries["note"] = note
        form.columnconfigure(1, weight=1)

        # Calcolo automatico nella schermata principale:
        # Importo consulenza = percentuale * importo finanziamento.
        # La descrizione compenso viene aggiornata da importo finanziamento e banca/istituto.
        for watched_key in ("importo_finanziamento", "percentuale", "banca"):
            ent = self.mandato_entries.get(watched_key)
            if ent:
                ent.bind("<KeyRelease>", lambda _e: self.update_financing_fields_live(False))
                ent.bind("<FocusOut>", lambda _e: self.update_financing_fields_live(True))

        if mandato_id:
            mrow = self.db.get_mandato(mandato_id)
            if mrow:
                self.fill_mandato_form(dict(mrow))

    def fill_mandato_form(self, data: Dict[str, Any]) -> None:
        combo: ttk.Combobox = self.mandato_entries["cliente_combo"]
        client_id = int(data.get("client_id") or 0)
        for label, cid in self.client_combo_map.items():
            if cid == client_id:
                combo.set(label)
                break
        for key, widget in self.mandato_entries.items():
            if key in ("cliente_combo", "client_summary"):
                continue
            value = data.get(key, "") or ""
            if isinstance(widget, tk.Text):
                widget.delete("1.0", "end")
                widget.insert("1.0", value)
            else:
                widget.delete(0, "end")
                widget.insert(0, value)
        self.load_client_summary()
        self.update_financing_fields_live(True)
        self.current_generated_docx = data.get("docx_path", "") or ""
        self.current_generated_pdf = data.get("pdf_path", "") or ""

    def collect_mandato_form(self) -> Dict[str, str]:
        data: Dict[str, str] = {}
        combo: ttk.Combobox = self.mandato_entries.get("cliente_combo")
        selected = combo.get() if combo else ""
        data["client_id"] = str(self.client_combo_map.get(selected, ""))
        for key, widget in self.mandato_entries.items():
            if key in ("cliente_combo", "client_summary"):
                continue
            if isinstance(widget, tk.Text):
                data[key] = widget.get("1.0", "end").strip()
            else:
                data[key] = widget.get().strip()
        if not data.get("luogo"):
            data["luogo"] = "Casagiove"
        if not data.get("data_mandato"):
            data["data_mandato"] = today_it()
        return data

    def get_selected_client(self) -> Optional[Dict[str, Any]]:
        combo: ttk.Combobox = self.mandato_entries.get("cliente_combo")
        if not combo:
            return None
        client_id = self.client_combo_map.get(combo.get())
        if not client_id:
            return None
        row = self.db.get_client(client_id)
        return dict(row) if row else None

    def load_client_summary(self) -> None:
        client = self.get_selected_client()
        widget: tk.Text = self.mandato_entries.get("client_summary")
        if not widget:
            return
        widget.configure(state="normal")
        widget.delete("1.0", "end")
        if not client:
            widget.insert("1.0", "Nessun cliente selezionato.")
        else:
            text = (
                f"AZIENDA\n"
                f"Denominazione: {client.get('denominazione','')}\n"
                f"Partita IVA: {client.get('partita_iva','')} - Codice fiscale: {client.get('codice_fiscale','')}\n"
                f"Sede legale: {client.get('sede_legale','')}\n"
                f"PEC: {client.get('pec','')} - Telefono: {client.get('telefono_azienda','')}\n"
                f"Codice attivita'/ATECO: {client.get('codice_ateco','')} - {client.get('settore_attivita','')}\n\n"
                f"AMMINISTRATORE\n"
                f"{client.get('amministratore_dati_completi') or build_admin_text(client)}"
            )
            widget.insert("1.0", text)
        widget.configure(state="disabled")

    def choose_mandato_attachment(self) -> None:
        path = filedialog.askopenfilename(title="Seleziona file allegato", filetypes=[("Documenti", "*.pdf *.docx *.xlsx *.xls *.png *.jpg"), ("Tutti i file", "*.*")])
        if not path:
            return
        copied = copy_to_folder(path, MANDATI_DIR / "allegati", "allegato")
        ent = self.mandato_entries.get("allegato_path")
        if ent:
            ent.delete(0, "end")
            ent.insert(0, copied or path)

    def insert_visura_from_mandato(self) -> None:
        client = self.get_selected_client()
        if not client:
            messagebox.showwarning(APP_NAME, "Seleziona prima un cliente.")
            return
        path = filedialog.askopenfilename(title="Seleziona visura camerale PDF", filetypes=[("PDF", "*.pdf"), ("Tutti i file", "*.*")])
        if not path:
            return
        try:
            data = parse_visura(path)
        except Exception as exc:
            messagebox.showerror(APP_NAME, f"Errore lettura visura:\n{exc}")
            return
        merged = dict(client)
        for key, val in data.items():
            if val:
                merged[key] = val
        if data.get("amministratore_dati_completi"):
            merged["amministratore_dati_completi"] = data["amministratore_dati_completi"]
        self.db.save_client(merged, int(client["id"]))
        copied = copy_to_folder(path, VISURE_DIR, safe_filename(merged.get("denominazione", "cliente")))
        old = self.db.last_visura_data(int(client["id"]))
        confronto = compare_data(old, data) if old else {}
        self.db.add_visura(int(client["id"]), copied or path, data, confronto)
        self.refresh_client_combo()
        self.load_client_summary()
        messagebox.showinfo(APP_NAME, "Visura collegata al cliente e dati aggiornati.")


    def insert_report_from_mandato(self) -> None:
        client = self.get_selected_client()
        if not client:
            messagebox.showwarning(APP_NAME, "Seleziona prima un cliente.")
            return
        path = filedialog.askopenfilename(title="Seleziona report PDF", filetypes=[("PDF", "*.pdf"), ("Tutti i file", "*.*")])
        if not path:
            return
        try:
            data = parse_report(path)
        except Exception as exc:
            messagebox.showerror(APP_NAME, f"Errore lettura report:\n{exc}")
            return

        merged = dict(client)
        for key, val in data.items():
            if val:
                merged[key] = val
        merged["amministratore_dati_completi"] = data.get("amministratore_dati_completi") or build_admin_text(merged)
        copied = copy_to_folder(path, REPORT_DIR, safe_filename(merged.get("denominazione", "report")) or "report")
        merged["report_path"] = copied or path
        self.db.save_client(merged, int(client["id"]))

        # Aggiorna la combo e mantiene selezionato lo stesso cliente.
        combo = self.mandato_entries.get("cliente_combo")
        if combo:
            values = self.refresh_client_combo()
            combo.configure(values=values)
            for label, cid in self.client_combo_map.items():
                if cid == int(client["id"]):
                    combo.set(label)
                    break
        self.load_client_summary()
        messagebox.showinfo(APP_NAME, "Report collegato al cliente e dati aggiornati.")

    def show_financing_window(self) -> None:
        win = tk.Toplevel(self)
        win.title("Dati Finanziamento")
        win.geometry("560x330")
        frame = ttk.Frame(win, padding=18)
        frame.pack(fill="both", expand=True)

        values = self.collect_mandato_form() if self.mandato_entries else {}
        fields = {}

        def add_row(r: int, label: str, key: str, default: str = "") -> ttk.Entry:
            ttk.Label(frame, text=label).grid(row=r, column=0, sticky="w", pady=8, padx=(0, 10))
            ent = ttk.Entry(frame, width=42)
            ent.grid(row=r, column=1, sticky="ew", pady=8)
            ent.insert(0, values.get(key, default))
            fields[key] = ent
            return ent

        importo_ent = add_row(0, "Importo finanziamento", "importo_finanziamento")
        percent_ent = add_row(1, "Percentuale", "percentuale")
        consulenza_ent = add_row(2, "Consulenza calcolata", "importo_consulenza")
        banca_ent = add_row(3, "Nome istituto / banca", "banca")
        descr_ent = add_row(4, "Descrizione compenso", "descrizione_compenso", "")
        frame.columnconfigure(1, weight=1)

        for live_ent in (importo_ent, percent_ent, banca_ent):
            live_ent.bind("<FocusOut>", lambda _e: calculate())

        def calculate() -> None:
            importo = parse_euro(importo_ent.get())
            percent = parse_percent(percent_ent.get())
            consulenza = importo * percent / 100.0 if importo and percent else 0.0
            if importo:
                importo_ent.delete(0, "end")
                importo_ent.insert(0, format_euro(importo))
            if percent:
                percent_ent.delete(0, "end")
                percent_ent.insert(0, format_percent(percent))
            consulenza_ent.delete(0, "end")
            consulenza_ent.insert(0, format_euro(consulenza) if consulenza else "")
            descrizione = build_descrizione_compenso(importo, banca_ent.get())
            descr_ent.delete(0, "end")
            descr_ent.insert(0, descrizione)

        def apply_to_form() -> None:
            calculate()
            if self.mandato_entries:
                mapping = {
                    "importo_finanziamento": importo_ent.get(),
                    "percentuale": percent_ent.get(),
                    "importo_consulenza": consulenza_ent.get(),
                    "banca": banca_ent.get(),
                    "descrizione_compenso": descr_ent.get(),
                }
                for key, val in mapping.items():
                    ent = self.mandato_entries.get(key)
                    if ent:
                        ent.delete(0, "end")
                        ent.insert(0, val)
            win.destroy()

        buttons = ttk.Frame(frame)
        buttons.grid(row=5, column=0, columnspan=2, pady=(18, 0), sticky="e")
        ttk.Button(buttons, text="Calcola", command=calculate).pack(side="left", padx=6)
        ttk.Button(buttons, text="Conferma", style="Accent.TButton", command=apply_to_form).pack(side="left", padx=6)
        ttk.Button(buttons, text="Chiudi", command=win.destroy).pack(side="left", padx=6)

    def update_financing_fields_live(self, format_fields: bool = False) -> None:
        """Aggiorna automaticamente consulenza e descrizione compenso nella form."""
        if getattr(self, "_updating_financial_fields", False):
            return
        if not getattr(self, "mandato_entries", None):
            return

        importo_ent = self.mandato_entries.get("importo_finanziamento")
        percent_ent = self.mandato_entries.get("percentuale")
        consulenza_ent = self.mandato_entries.get("importo_consulenza")
        banca_ent = self.mandato_entries.get("banca")
        descr_ent = self.mandato_entries.get("descrizione_compenso")
        if not (importo_ent and percent_ent and consulenza_ent):
            return

        self._updating_financial_fields = True
        try:
            importo_num = parse_euro(importo_ent.get())
            percent_num = parse_percent(percent_ent.get())

            if importo_num and percent_num:
                consulenza_ent.delete(0, "end")
                consulenza_ent.insert(0, format_euro(importo_num * percent_num / 100.0))

            if format_fields:
                if importo_num:
                    importo_ent.delete(0, "end")
                    importo_ent.insert(0, format_euro(importo_num))
                if percent_num:
                    percent_ent.delete(0, "end")
                    percent_ent.insert(0, format_percent(percent_num))

            banca_txt = banca_ent.get() if banca_ent else ""
            descrizione = build_descrizione_compenso(importo_num, banca_txt)
            if descrizione and descr_ent:
                descr_ent.delete(0, "end")
                descr_ent.insert(0, descrizione)
        finally:
            self._updating_financial_fields = False

    def save_mandato_from_form(self) -> Optional[int]:
        self.update_financing_fields_live(True)
        data = normalize_financing_data(self.collect_mandato_form())
        if not data.get("client_id"):
            messagebox.showwarning(APP_NAME, "Seleziona un cliente.")
            return None
        mandato_id = self.db.save_mandato(data, self.current_mandato_id)
        self.current_mandato_id = mandato_id
        messagebox.showinfo(APP_NAME, "Mandato salvato correttamente.")
        return mandato_id

    def validate_mandato_ready(self, client: Dict[str, Any], mandato: Dict[str, str]) -> bool:
        missing = []
        for label, key in [
            ("dati amministratore completi", "amministratore_dati_completi"),
            ("nome amministratore", "amministratore_nome"),
            ("denominazione azienda", "denominazione"),
            ("importo finanziamento", "importo_finanziamento"),
            ("importo consulenza", "importo_consulenza"),
            ("banca", "banca"),
        ]:
            source = client if key.startswith("amministratore") or key == "denominazione" else mandato
            if not clean_inline(source.get(key, "")):
                missing.append(label)
        if missing:
            messagebox.showwarning(
                APP_NAME,
                "Prima di generare il mandato completare:\n- " + "\n- ".join(missing) +
                "\n\nNota: i dati amministratore sono modificabili nella scheda Nuovo Cliente.",
            )
            return False
        return True

    def generate_definitive_mandato(self) -> None:
        client = self.get_selected_client()
        if not client:
            messagebox.showwarning(APP_NAME, "Seleziona un cliente.")
            return
        self.update_financing_fields_live(True)
        mandato = normalize_financing_data(self.collect_mandato_form())
        for k in ["importo_finanziamento", "percentuale", "importo_consulenza", "descrizione_compenso"]:
            ent = self.mandato_entries.get(k)
            if ent:
                ent.delete(0, "end")
                ent.insert(0, mandato.get(k, ""))
        if not self.validate_mandato_ready(client, mandato):
            return
        mandato_id = self.db.save_mandato(mandato, self.current_mandato_id)
        self.current_mandato_id = mandato_id
        template = DEFAULT_TEMPLATE
        if not template.exists():
            selected = filedialog.askopenfilename(title="Seleziona Mandato_vuoto.docx", filetypes=[("Word", "*.docx")])
            if not selected:
                return
            template = Path(selected)
        name = safe_filename(f"Mandato_{client.get('denominazione','cliente')}_{today_it().replace('/', '-')}")
        out_docx = MANDATI_DIR / f"{name}.docx"
        try:
            generated_docx = generate_mandato_docx(str(template), str(out_docx), client, mandato)
        except Exception as exc:
            messagebox.showerror(APP_NAME, f"Errore generazione DOCX:\n{exc}")
            return
        generated_pdf = convert_docx_to_pdf(generated_docx, str(MANDATI_DIR))
        self.current_generated_docx = generated_docx
        self.current_generated_pdf = generated_pdf
        self.db.update_mandato_paths(mandato_id, generated_docx, generated_pdf)
        if generated_pdf:
            messagebox.showinfo(APP_NAME, f"Mandato definitivo generato:\n{generated_pdf}")
        else:
            messagebox.showwarning(
                APP_NAME,
                "Mandato DOCX generato correttamente.\n\nIl PDF non e' stato creato perche' non risulta disponibile Microsoft Word o LibreOffice/soffice.\n"
                f"File DOCX:\n{generated_docx}"
            )

    def ensure_pdf_generated(self) -> bool:
        if self.current_generated_pdf and Path(self.current_generated_pdf).exists():
            return True
        if self.current_generated_docx and Path(self.current_generated_docx).exists():
            pdf = convert_docx_to_pdf(self.current_generated_docx, str(MANDATI_DIR))
            if pdf:
                self.current_generated_pdf = pdf
                if self.current_mandato_id:
                    self.db.update_mandato_paths(self.current_mandato_id, pdf_path=pdf)
                return True
        self.generate_definitive_mandato()
        return bool(self.current_generated_pdf and Path(self.current_generated_pdf).exists())

    def preview_pdf(self) -> None:
        if self.ensure_pdf_generated():
            open_file(self.current_generated_pdf)
        elif self.current_generated_docx and Path(self.current_generated_docx).exists():
            open_file(self.current_generated_docx)

    def save_pdf_as(self) -> None:
        if not self.ensure_pdf_generated():
            messagebox.showwarning(APP_NAME, "PDF non disponibile. Genera prima il mandato definitivo oppure installa Microsoft Word o LibreOffice/soffice.")
            return
        dest = filedialog.asksaveasfilename(
            title="Salva PDF",
            defaultextension=".pdf",
            filetypes=[("PDF", "*.pdf")],
            initialfile=Path(self.current_generated_pdf).name,
        )
        if not dest:
            return
        shutil.copy2(self.current_generated_pdf, dest)
        messagebox.showinfo(APP_NAME, f"PDF salvato:\n{dest}")

    def print_current_pdf(self) -> None:
        if self.ensure_pdf_generated():
            print_file(self.current_generated_pdf)
        else:
            messagebox.showwarning(APP_NAME, "PDF non disponibile per la stampa.")

    def show_mandati_list(self) -> None:
        self.clear()
        self.header(self, "Elenco Mandati", "Doppio clic per aprire/modificare un mandato.")
        top = ttk.Frame(self, padding=(18, 0, 18, 10))
        top.pack(fill="x")
        ttk.Button(top, text="Nuovo Mandato", command=lambda: self.show_new_mandato(None)).pack(side="left")
        ttk.Button(top, text="Indietro", command=self.show_mandato_menu).pack(side="right")

        cols = ("id", "cliente", "data", "stato", "importo", "banca", "pdf")
        tree = ttk.Treeview(self, columns=cols, show="headings")
        labels = {"id": "ID", "cliente": "Cliente", "data": "Data", "stato": "Stato", "importo": "Consulenza", "banca": "Banca", "pdf": "PDF"}
        widths = {"id": 60, "cliente": 260, "data": 100, "stato": 120, "importo": 130, "banca": 180, "pdf": 220}
        for col in cols:
            tree.heading(col, text=labels[col])
            tree.column(col, width=widths[col])
        tree.pack(fill="both", expand=True, padx=18, pady=(0, 18))
        for row in self.db.get_mandati():
            tree.insert("", "end", iid=str(row["id"]), values=(row["id"], row["cliente"], row["data_mandato"], row["stato"], row["importo_consulenza"], row["banca"], Path(row["pdf_path"] or "").name))
        tree.bind("<Double-1>", lambda e: self._open_mandato_from_tree(tree))

    def _open_mandato_from_tree(self, tree: ttk.Treeview) -> None:
        sel = tree.selection()
        if sel:
            self.show_new_mandato(int(sel[0]))

    # ------------------------------ Report ----------------------------------

    def show_report(self) -> None:
        self.clear()
        self.header(self, "Report", "Riepilogo archivio offline.")
        top = ttk.Frame(self, padding=(18, 0, 18, 10))
        top.pack(fill="x")
        ttk.Button(top, text="Aggiorna", command=self.show_report).pack(side="left")
        ttk.Button(top, text="Indietro", command=self.show_home).pack(side="right")

        clients = self.db.get_clients()
        mandati = self.db.get_mandati()
        box = tk.Text(self, wrap="word", font=("Consolas", 10))
        box.pack(fill="both", expand=True, padx=18, pady=(0, 18))
        box.insert("end", f"Clienti salvati: {len(clients)}\n")
        box.insert("end", f"Mandati salvati: {len(mandati)}\n")
        box.insert("end", f"Archivio: {DATA_DIR}\n\n")
        box.insert("end", "CLIENTI\n")
        box.insert("end", "-" * 80 + "\n")
        for c in clients:
            box.insert("end", f"{c['id']:>3} | {c['denominazione'] or ''} | PIVA {c['partita_iva'] or ''} | Admin {c['amministratore_nome'] or ''}\n")
        box.insert("end", "\nMANDATI\n")
        box.insert("end", "-" * 80 + "\n")
        for m in mandati:
            box.insert("end", f"{m['id']:>3} | {m['cliente'] or ''} | {m['data_mandato'] or ''} | {m['importo_consulenza'] or ''} | {m['banca'] or ''}\n")
        box.configure(state="disabled")


def main() -> None:
    app = FinancePlusApp()
    app.mainloop()


if __name__ == "__main__":
    main()
